using Microsoft.AspNetCore.Authorization;

namespace MyApp.Controllers
{
    // Policy setup: In Startup/Program.cs, add an authorization policy named "FetchPolicy"
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "FetchPolicy")]
    public class MyController : ControllerBase
    {
        private readonly IFetchContentService _fetchContentService;
        private readonly IHostAllowlistValidator _hostAllowlistValidator;

        public MyController(IFetchContentService fetchContentService, IHostAllowlistValidator hostAllowlistValidator)
        {
            _fetchContentService = fetchContentService;
            _hostAllowlistValidator = hostAllowlistValidator;
        }

        [HttpPost("fetch")]
        [Authorize(Policy = "FetchPolicy")]
        public async Task<IActionResult> FetchContent([FromBody] FetchContentRequestDto request)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(new { error = "Invalid input." });
            }

            try
            {
                _hostAllowlistValidator.ValidateHostIsAllowed(request.Host);

                var content = await _fetchContentService.FetchContentFromHostAsync(request.Host);

                return Ok(content);
            }
            catch (HostAllowlistViolationException)
            {
                return NotFound(new { error = "Host not allowed." });
            }
            catch (FetchContentException ex)
            {
                return BadRequest(new { error = ex.Message });
            }
            catch (Exception ex)
            {
                // Logging should be done using a dedicated logging framework/interface
                Console.Error.WriteLine(ex.Message);
                return StatusCode(500, new { error = "Internal server error." });
            }
        }
    }
}

