// Services/FetchContentService.cs
using System;
using System.Net.Http;
using System.Threading.Tasks;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Configuration;

namespace MyApp
{
    public class FetchContentService : IFetchContentService
    {
        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<FetchContentService> _logger;
        private readonly IConfiguration _configuration;

        public FetchContentService(
            IHttpClientFactory httpClientFactory,
            ILogger<FetchContentService> logger,
            IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        public async Task<string> FetchContentFromHostAsync(string host)
        {
            // Never hardcode or concatenate user input in URL construction
            // Host allowlist validation should have occurred earlier
            var baseUrl = $"https://{host}/";

            var client = _httpClientFactory.CreateClient("SafeFetchClient");
            client.Timeout = TimeSpan.FromSeconds(_configuration.GetValue<int?>("Fetcher:TimeoutSeconds") ?? 10);
            client.DefaultRequestHeaders.Clear();

            var url = BuildAndValidateFinalUrl(baseUrl);

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("MyAppFetcher/1.0");

            HttpResponseMessage response;
            try
            {
                response = await client.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Failed to fetch from {Host}", host);
                throw new FetchContentException("Failed to fetch content.");
            }

            if (!response.IsSuccessStatusCode)
            {
                _logger.LogWarning("Non-success status code {StatusCode} for {Host}", response.StatusCode, host);
                throw new FetchContentException("Content not available.");
            }

            var content = await response.Content.ReadAsStringAsync();

            return content;
        }

        private Uri BuildAndValidateFinalUrl(string baseUrl)
        {
            // Only allow HTTPS, no redirects, no intermediate redirects
            // Optionally: validate the URI for defense-in-depth
            try
            {
                var uri = new Uri(baseUrl, UriKind.Absolute);
                if (!string.Equals(uri.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase))
                {
                    throw new FetchContentException("Only HTTPS URLs are allowed.");
                }
                return uri;
            }
            catch (Exception)
            {
                throw new FetchContentException("Invalid URL.");
            }
        }
    }
}

// Services/HostAllowlistValidator.cs
using System;
using System.Collections.ObjectModel;
using System.Linq;

namespace MyApp
{
    public class HostAllowlistViolationException : Exception { }

    public class HostAllowlistValidator : IHostAllowlistValidator
    {
        private readonly ReadOnlyCollection<string> _allowedHosts;

        public HostAllowlistValidator(ReadOnlyCollection<string> allowedHosts)
        {
            _allowedHosts = allowedHosts;
        }

        public void ValidateHostIsAllowed(string host)
        {
            if (string.IsNullOrWhiteSpace(host))
            {
                throw new HostAllowlistViolationException();
            }

            // Only allow exactly-match allowed hosts (canonicalized, without trailing dot if any)
            var canonicalHost = host.Trim().ToLowerInvariant();

            if (_allowedHosts.Any(allow =>
                string.Equals(canonicalHost, allow.Trim().ToLowerInvariant(), StringComparison.Ordinal)))
            {
                return;
            }

            throw new HostAllowlistViolationException();
        }
    }
}

