namespace MyApp.Controllers
{
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "UrlPreviewPolicy")]
    public class UrlPreviewController : ControllerBase
    {
        private static readonly string[] AllowedDomains = new[]
        {
            "example.com", // Add allowed domains here
            "www.example.com"
        };

        private static readonly string[] AllowedSchemes = new[] { "https" };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<UrlPreviewController> _logger;
        private readonly IConfiguration _configuration;

        public UrlPreviewController(IHttpClientFactory httpClientFactory, ILogger<UrlPreviewController> logger, IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost]
        [Authorize(Policy = "UrlPreviewPolicy")]
        public async Task<IActionResult> FetchPreviewContent([FromBody] UrlPreviewRequestDto request)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(new { error = "Invalid input." });
            }

            try
            {
                var validatedUri = UrlValidationHelper.ValidateAndCanonicalizeUrl(request.Url, AllowedSchemes, AllowedDomains, _logger);
                if (validatedUri == null)
                {
                    _logger.LogWarning("Blocked request for invalid or disallowed URL: {Url}", request.Url);
                    return BadRequest(new { error = "The provided URL is not allowed." });
                }

                var httpClient = _httpClientFactory.CreateClient("UrlPreviewSafeClient");
                httpClient.Timeout = TimeSpan.FromSeconds(_configuration.GetValue<int?>("UrlPreview:TimeoutSeconds") ?? 5);
                httpClient.DefaultRequestHeaders.Clear();

                using var httpRequest = new HttpRequestMessage(HttpMethod.Get, validatedUri);
                httpRequest.Headers.Accept.ParseAdd("text/html");

                using var response = await httpClient.SendAsync(httpRequest, HttpCompletionOption.ResponseHeadersRead, HttpContext.RequestAborted);

                if (response.StatusCode != HttpStatusCode.OK)
                {
                    _logger.LogWarning("Non-OK status code {StatusCode} for URL {Url}", response.StatusCode, validatedUri.ToString());
                    return NotFound(new { error = "Could not retrieve content from the provided URL." });
                }

                var contentType = response.Content.Headers.ContentType?.MediaType ?? string.Empty;
                if (!contentType.StartsWith("text/html", StringComparison.OrdinalIgnoreCase))
                {
                    _logger.LogWarning("Blocked non-HTML content type {ContentType} for URL {Url}", contentType, validatedUri.ToString());
                    return BadRequest(new { error = "The provided URL does not point to an HTML page." });
                }

                var content = await response.Content.ReadAsStringAsync(HttpContext.RequestAborted);
                return Ok(content);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error fetching preview content for URL {Url}", request.Url);
                return StatusCode(500, new { error = "Internal server error." });
            }
        }
    }
}

