// Helpers/UrlValidationHelper.cs
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Sockets;
using System.Text.RegularExpressions;
using Microsoft.Extensions.Logging;

namespace MyApp.Helpers
{
    public static class UrlValidationHelper
    {
        private static readonly string[] AllowedSchemes = new[] { "https" };
        private static readonly HashSet<string> AllowedDomains = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "example.com",
            "www.example.com"
        };

        public static Uri? ValidateAndCanonicalizeUrl(string inputUrl, string[] allowedSchemes, HashSet<string> allowedDomains, ILogger logger)
        {
            if (!Uri.TryCreate(inputUrl, UriKind.Absolute, out var uri))
            {
                return null;
            }

            if (!AllowedSchemes.Contains(uri.Scheme, StringComparer.OrdinalIgnoreCase))
            {
                return null;
            }

            if (!allowedDomains.Contains(uri.Host))
            {
                return null;
            }

            // Defense-in-depth: resolve DNS and check IP ranges
            try
            {
                var hostAddresses = Dns.GetHostAddresses(uri.Host);
                foreach (var ip in hostAddresses)
                {
                    if (IsIpAddressUnsafe(ip))
                    {
                        logger.LogWarning("Blocked due to unsafe IP address: {Ip}", ip);
                        return null;
                    }
                }
            }
            catch
            {
                return null;
            }

            return uri;
        }

        private static bool IsIpAddressUnsafe(IPAddress ip)
        {
            if (ip.AddressFamily == AddressFamily.InterNetwork || ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (IPAddress.IsLoopback(ip) ||
                    ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal ||
                    ip.IsIPv6Teredo ||
                    ip.Equals(IPAddress.Any) ||
                    ip.Equals(IPAddress.IPv6Any) ||
                    ip.Equals(IPAddress.Broadcast) ||
                    (ip.AddressFamily == AddressFamily.InterNetwork && IsPrivateIPv4(ip)))
                {
                    return true;
                }
            }
            return false;
        }

        private static bool IsPrivateIPv4(IPAddress ip)
        {
            var bytes = ip.GetAddressBytes();
            return
                (bytes[0] == 10) ||
                (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31) ||
                (bytes[0] == 192 && bytes[1] == 168);
        }
    }
}

