    [Authorize(Policy = "UrlPreviewPolicy")]
    public class UrlPreviewController : ControllerBase
    {
        private static readonly HashSet<string> AllowedDomains = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            // Add your allowlisted domains here
            "example.com",
            "www.example.com"
        };

        private static readonly HashSet<string> AllowedSchemes = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

