            catch (UrlPreviewValidationException ex)
            {
                _logger.LogWarning("URL validation failed: {Reason}", ex.Message);
                return BadRequest(new { error = "URL validation failed." });
            }
            catch (HttpRequestException ex)
            {
                _logger.LogWarning("HTTP request failed: {Reason}", ex.Message);
                return BadRequest(new { error = "Unable to fetch preview." });
