        public static async Task<string> FetchSecureUrlAsync(IHttpClientFactory httpClientFactory, Uri uri)
        {
            var client = httpClientFactory.CreateClient(nameof(UrlPreviewService));
            client.Timeout = TimeSpan.FromSeconds(10);
            client.DefaultRequestHeaders.Clear();

            var request = new HttpRequestMessage(HttpMethod.Get, uri);
            request.Headers.Add("User-Agent", "UrlPreviewBot/1.0");

            var response = await client.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);

            if (!response.IsSuccessStatusCode)
            {
                throw new HttpRequestException($"Failed to fetch URL preview: {response.StatusCode}");
            }

            var contentType = response.Content.Headers.ContentType?.MediaType ?? "";
            if (!contentType.StartsWith("text/html", StringComparison.OrdinalIgnoreCase))
            {
                throw new HttpRequestException("Content is not HTML.");
            }

            var content = await response.Content.ReadAsStringAsync();

            return content;
        }
    }
}

// Utils/UrlValidator.cs
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Sockets;

namespace UrlPreview.Utils
{
    public static class UrlValidator
    {
        public static Uri ValidateAndCanonicalizeUrl(string inputUrl, HashSet<string> allowedSchemes, HashSet<string> allowedDomains)
        {
            if (string.IsNullOrWhiteSpace(inputUrl))
            {
                throw new UrlPreviewValidationException("URL is required.");
            }

            if (!Uri.TryCreate(inputUrl, UriKind.Absolute, out var uri))
            {
                throw new UrlPreviewValidationException("Invalid URL format.");
            }

            if (!allowedSchemes.Contains(uri.Scheme))
            {
                throw new UrlPreviewValidationException("Only HTTPS URLs are allowed.");
            }

            var host = uri.Host.TrimEnd('.').ToLowerInvariant();

            if (!allowedDomains.Contains(host))
            {
                throw new UrlPreviewValidationException("Domain is not allowlisted.");
            }

            var addresses = Dns.GetHostAddresses(host);

            foreach (var address in addresses)
            {
                if (IsPrivateAddress(address))
                {
                    throw new UrlPreviewValidationException("Access to private or internal addresses is not allowed.");
                }
            }

            return new UriBuilder(uri.Scheme, host, uri.Port, uri.AbsolutePath, uri.Query).Uri;
        }

        private static bool IsPrivateAddress(IPAddress address)
        {
            if (address.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = address.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 127.0.0.0/8
                if (bytes[0] == 127)
                {
                    return true;
                }
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
            }
            else if (address.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (address.IsIPv6LinkLocal || address.IsIPv6Multicast || address.IsIPv6SiteLocal || address.IsIPv6Teredo)
                {
                    return true;
                }
                // ::1/128 (loopback)
                if (address.Equals(IPAddress.IPv6Loopback))
                {
                    return true;
                }
                // fc00::/7 (unique local)
                var bytes = address.GetAddressBytes();
                if ((bytes[0] & 0xfe) == 0xfc)
                {
                    return true;
                }
            }
            return false;
        }
    }
}

