using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace YourNamespace.Controllers
{
    // Policy setup: In Startup/Program, configure an authorization policy named "WebhookFetchPolicy"
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "WebhookFetchPolicy")]
    public class WebhookController : ControllerBase
    {
        private static readonly HashSet<string> AllowedHosts = new(StringComparer.OrdinalIgnoreCase)
        {
            // Add allowed domains/hosts here
            "example.com",
            "api.example.com"
        };

        private static readonly HashSet<string> AllowedSchemes = new(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly IConfiguration _configuration;

        public WebhookController(
            IHttpClientFactory httpClientFactory,
            ILogger<WebhookController> logger,
            IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("fetch")]
        [Authorize(Policy = "WebhookFetchPolicy")]
        public async Task<IActionResult> FetchDataAsync([FromBody] WebhookFetchRequestDto request)
        {
            _logger.LogInformation("Webhook fetch requested for inputId {InputId}", request?.Id);

            if (request == null || string.IsNullOrWhiteSpace(request.Id))
            {
                return BadRequest(new { error = "Invalid request." });
            }

            try
            {
                // Only allow fetch from explicitly allowed hosts/URLs
                if (!TryValidateAllowedWebhookUrl(request.Id, out var validatedUri))
                {
                    _logger.LogWarning("Rejected webhook fetch: Input {InputId} failed validation.", request.Id);
                    return BadRequest(new { error = "Destination is not allowed." });
                }

                var client = _httpClientFactory.CreateClient("WebhookSafeClient");
                client.Timeout = TimeSpan.FromSeconds(10);

                // Prevent automatic redirects to avoid SSRF via redirect
                var requestMessage = new HttpRequestMessage(HttpMethod.Get, validatedUri);

                using var response = await client.SendAsync(requestMessage, HttpCompletionOption.ResponseHeadersRead, HttpContext.RequestAborted);

                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Webhook fetch failed for {InputId} with status {StatusCode}", request.Id, response.StatusCode);
                    return StatusCode((int)response.StatusCode, new { error = "Failed to fetch data." });
                }

                var contentType = response.Content.Headers.ContentType?.MediaType ?? "";
                if (contentType != "application/json" && contentType != "text/plain")
                {
                    _logger.LogWarning("Webhook fetch {InputId} returned unexpected content type: {ContentType}", request.Id, contentType);
                    return BadRequest(new { error = "Invalid content type." });
                }

                var data = await response.Content.ReadAsStringAsync();
                _logger.LogInformation("Webhook fetch {InputId} succeeded.", request.Id);
                return Ok(data);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error fetching webhook data for inputId {InputId}", request.Id);
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private bool TryValidateAllowedWebhookUrl(string inputId, out Uri validatedUri)
        {
            validatedUri = null;
            if (!Uri.TryCreate(inputId, UriKind.Absolute, out var inputUri))
            {
                return false;
            }

            if (!AllowedSchemes.Contains(inputUri.Scheme))
            {
                return false;
            }

            // Canonicalize host
            var host = inputUri.Host.TrimEnd('.').ToLowerInvariant();

            if (!AllowedHosts.Contains(host))
            {
                return false;
            }

            // Resolve host to IPs and block non-public ranges
            try
            {
                var hostAddresses = Dns.GetHostAddresses(host);
                foreach (var ip in hostAddresses)
                {
                    if (IsIpAddressUnsafe(ip))
                    {
                        return false;
                    }
                }
            }
            catch
            {
                return false;
            }

            validatedUri = new UriBuilder(inputUri.Scheme, host, inputUri.Port, inputUri.AbsolutePath, inputUri.Query).Uri;
            return true;
        }

        private static bool IsIpAddressUnsafe(IPAddress ip)
        {
            if (IPAddress.IsLoopback(ip))
            {
                return true;
            }

            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                // IPv4
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 127.0.0.0/8
                if (bytes[0] == 127)
                {
                    return true;
                }
                // Link-local 169.254.0.0/16
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
                // Broadcast/unspecified
                if (ip.Equals(IPAddress.Broadcast) || ip.Equals(IPAddress.Any))
                {
                    return true;
                }
            }
            else if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                // IPv6
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo || ip.IsIPv6UniqueLocal)
                {
                    return true;
                }
                // ::1/128 loopback
                if (ip.Equals(IPAddress.IPv6Loopback))
                {
                    return true;
                }
                // ::/128 unspecified
                if (ip.Equals(IPAddress.IPv6None))
                {
                    return true;
                }
            }

            return false;
        }
    }
}

