namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "ImagePreviewPolicy")]
    public class ImagePreviewController : ControllerBase
    {
        private static readonly HashSet<string> AllowedDomains = new(StringComparer.OrdinalIgnoreCase)
        {
            // Add allowed domains here
            "example.com",
            "images.examplecdn.com"
        };

        private static readonly HashSet<string> AllowedSchemes = new(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<ImagePreviewController> _logger;
        private readonly IConfiguration _configuration;

        public ImagePreviewController(
            IHttpClientFactory httpClientFactory,
            ILogger<ImagePreviewController> logger,
            IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("preview")]
        [Authorize(Policy = "ImagePreviewPolicy")]
        public async Task<IActionResult> GetImagePreview([FromBody] ImagePreviewRequestDto request)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(new { error = "Invalid input." });
            }

            try
            {
                if (!TryValidateAndCanonicalizeUrl(request.ImageUrl, out var validatedUri, out var validationError))
                {
                    _logger.LogWarning("Rejected image URL: {ImageUrl} Reason: {Reason}", request.ImageUrl, validationError);
                    return BadRequest(new { error = "Invalid or unapproved image URL." });
                }

                if (!await IsPublicAddressAsync(validatedUri))
                {
                    _logger.LogWarning("Rejected non-public image URL: {ImageUrl}", request.ImageUrl);
                    return BadRequest(new { error = "Image URL is not allowed." });
                }

                using var client = _httpClientFactory.CreateClient(nameof(ImagePreviewController));
                client.Timeout = TimeSpan.FromSeconds(10);
                client.DefaultRequestHeaders.Clear();
                client.MaxResponseContentBufferSize = 3 * 1024 * 1024; // 3MB max

                using var response = await client.GetAsync(validatedUri, HttpCompletionOption.ResponseHeadersRead);
                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Image fetch failed: {StatusCode} {ImageUrl}", response.StatusCode, request.ImageUrl);
                    return BadRequest(new { error = "Failed to fetch image." });
                }

                var contentType = response.Content.Headers.ContentType?.MediaType ?? string.Empty;
                if (!contentType.StartsWith("image/", StringComparison.OrdinalIgnoreCase))
                {
                    _logger.LogWarning("Rejected non-image content type: {ContentType} {ImageUrl}", contentType, request.ImageUrl);
                    return BadRequest(new { error = "The content is not an image." });
                }

                var stream = await response.Content.ReadAsStreamAsync();
                return File(stream, contentType);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error fetching or validating image preview.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private static bool TryValidateAndCanonicalizeUrl(string url, out Uri validatedUri, out string error)
        {
            validatedUri = null;
            error = null;

            if (string.IsNullOrWhiteSpace(url))
            {
                error = "URL is empty.";
                return false;
            }

            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri))
            {
                error = "URL is not valid.";
                return false;
            }

            if (!AllowedSchemes.Contains(uri.Scheme))
            {
                error = "Scheme is not allowed.";
                return false;
            }

            if (string.IsNullOrEmpty(uri.Host))
            {
                error = "Host is missing.";
                return false;
            }

            // Only allow specific domains
            if (!AllowedDomains.Contains(uri.Host))
            {
                error = "Domain is not allowed.";
                return false;
            }

            validatedUri = new UriBuilder(uri.Scheme, uri.Host, uri.Port, uri.AbsolutePath, uri.Query).Uri;
            return true;
        }

        private static async Task<bool> IsPublicAddressAsync(Uri uri)
        {
            try
            {
                var host = uri.Host;
                var addresses = await Dns.GetHostAddressesAsync(host);

                foreach (var address in addresses)
                {
                    if (IsPrivateOrLocalIp(address))
                    {
                        return false;
                    }
                }
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool IsPrivateOrLocalIp(IPAddress address)
        {
            if (IPAddress.IsLoopback(address))
            {
                return true;
            }

            if (address.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = address.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
            }
            else if (address.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (address.IsIPv6LinkLocal || address.IsIPv6SiteLocal || address.IsIPv6Multicast)
                {
                    return true;
                }
                if (address.Equals(IPAddress.IPv6Loopback))
                {
                    return true;
                }
            }
            return false;
        }
    }
}

