// Services/ExternalContentFetcher.cs
using System;
using System.Collections.Generic;
using System.Net;
using System.Net.Http;
using System.Threading.Tasks;

public class ExternalContentFetcher : IExternalContentFetcher
{
    private static readonly IReadOnlyDictionary<string, string> AllowedHosts = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase)
    {
        // Add approved hosts or domains only
        { "example.com", "https://example.com" },
        { "api.example.com", "https://api.example.com" },
    };

    private readonly IHttpClientFactory _httpClientFactory;

    public ExternalContentFetcher(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    public async Task<string> FetchContentFromAllowlistedUrlAsync(string allowlistedHostKey)
    {
        if (!AllowedHosts.TryGetValue(allowlistedHostKey, out var allowedUrl))
        {
            throw new ExternalContentFetchException("Host is not allowed.");
        }

        if (!Uri.TryCreate(allowedUrl, UriKind.Absolute, out var uri))
        {
            throw new ExternalContentFetchException("Invalid allowed URL.");
        }

        if (!IsSafeScheme(uri))
        {
            throw new ExternalContentFetchException("Only HTTPS is allowed.");
        }

        if (!IsPublicAddress(uri.Host))
        {
            throw new ExternalContentFetchException("Target address is not allowed.");
        }

        var httpClient = _httpClientFactory.CreateClient();
        httpClient.Timeout = TimeSpan.FromSeconds(10);

        var request = new HttpRequestMessage(HttpMethod.Get, uri);
        request.Headers.Accept.Clear();
        request.Headers.UserAgent.ParseAdd("MyApp-ExternalFetcher/1.0");

        using var response = await httpClient.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);
        if (!response.IsSuccessStatusCode)
        {
            throw new ExternalContentFetchException("Failed to fetch content.");
        }

        var contentType = response.Content.Headers.ContentType?.MediaType ?? "";
        if (contentType != "text/html" && contentType != "application/json")
        {
            throw new ExternalContentFetchException("Content-Type not allowed.");
        }

        var content = await response.Content.ReadAsStringAsync();
        return content;
    }

    private static bool IsSafeScheme(Uri uri)
    {
        return uri.Scheme.Equals(Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase);
    }

    private static bool IsPublicAddress(string host)
    {
        try
        {
            var addresses = Dns.GetHostAddresses(host);
            foreach (var address in addresses)
            {
                if (IsIpPrivateOrLocal(address))
                {
                    return false;
                }
            }
            return true;
        }
        catch
        {
            return false;
        }
    }

    private static bool IsIpPrivateOrLocal(IPAddress ip)
    {
        if (IPAddress.IsLoopback(ip))
        {
            return true;
        }

        if (ip.AddressFamily == System.Net.Sockets.AddressFamily.InterNetwork)
        {
            byte[] bytes = ip.GetAddressBytes();
            // 10.0.0.0/8
            if (bytes[0] == 10)
            {
                return true;
            }
            // 172.16.0.0/12
            if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
            {
                return true;
            }
            // 192.168.0.0/16
            if (bytes[0] == 192 && bytes[1] == 168)
            {
                return true;
            }
            // 169.254.0.0/16 (link-local)
            if (bytes[0] == 169 && bytes[1] == 254)
            {
                return true;
            }
        }
        else if (ip.AddressFamily == System.Net.Sockets.AddressFamily.InterNetworkV6)
        {
            if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo || ip.IsIPv6UniqueLocal)
            {
                return true;
            }
            if (ip.Equals(IPAddress.IPv6Loopback))
            {
                return true;
            }
        }
        return false;
    }
}

