using FileUpload.Models;
using FileUpload.Services;

namespace FileUpload.Controllers
{
    // Policy setup required in Program.cs or Startup.cs:
    // options.AddPolicy("FileUploadPolicy", policy => policy.RequireAuthenticatedUser());
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "FileUploadPolicy")]
    public class FileUploadController : ControllerBase
    {
        private readonly IFileStorageService _fileStorageService;
        private readonly ILogger<FileUploadController> _logger;
        private readonly IConfiguration _configuration;

        public FileUploadController(
            IFileStorageService fileStorageService,
            ILogger<FileUploadController> logger,
            IConfiguration configuration)
        {
            _fileStorageService = fileStorageService;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("upload")]
        [Authorize(Policy = "FileUploadPolicy")]
        [RequestSizeLimit(10 * 1024 * 1024)] // 10 MB max
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> UploadFile([FromForm] FileUploadRequest request, CancellationToken cancellationToken)
        {
            _logger.LogInformation("File upload attempt. Name: {FileName}, Size: {FileSize}", request.File?.FileName, request.File?.Length);

            if (!ModelState.IsValid)
            {
                return BadRequest(new { error = "Invalid request data." });
            }

            string[] allowedExtensions = _configuration.GetSection("FileUpload:AllowedExtensions").Get<string[]>() ?? new[] { ".jpg", ".jpeg", ".png", ".pdf", ".docx" };
            long maxFileSize = _configuration.GetValue<long>("FileUpload:MaxFileSize", 10 * 1024 * 1024);

            string safeFileName = FileNameHelper.GenerateSafeFileName(request.File?.FileName, allowedExtensions);
            if (string.IsNullOrEmpty(safeFileName))
            {
                _logger.LogWarning("File upload rejected due to invalid filename or extension.");
                return BadRequest(new { error = "Invalid file name or extension." });
            }

            MemoryStream fileStream = new MemoryStream();
            await request.File.CopyToAsync(fileStream, cancellationToken);
            fileStream.Position = 0;

            if (!FileSignatureValidator.IsValidSignature(fileStream, safeFileName))
            {
                _logger.LogWarning("File upload rejected due to invalid signature.");
                return BadRequest(new { error = "File content does not match the extension." });
            }

            fileStream.Position = 0;
            string storagePath = await _fileStorageService.SaveFileAsync(safeFileName, fileStream, maxFileSize, cancellationToken);

            _logger.LogInformation("File uploaded successfully: {StoragePath}", storagePath);

            return Ok(new { message = "File uploaded successfully." });
        }
    }
}

