using System;
using System.Collections.Generic;
using System.IO;

namespace FileUpload.Models
{
    public static class FileSignatureValidator
    {
        // Basic file signature allowlist for demo purposes; extend as needed.
        private static readonly Dictionary<string, byte[][]> Signatures = new Dictionary<string, byte[][]>
        {
            { ".jpg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
            { ".jpeg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
            { ".png", new[] { new byte[] { 0x89, 0x50, 0x4E, 0x47 } } },
            { ".pdf", new[] { new byte[] { 0x25, 0x50, 0x44, 0x46 } } },
            { ".docx", new[] { new byte[] { 0x50, 0x4B, 0x03, 0x04 } } }
        };

        public static bool IsValidSignature(Stream fileStream, string extension)
        {
            if (!Signatures.TryGetValue(extension.ToLowerInvariant(), out var validSigs))
            {
                return false;
            }

            long originalPosition = fileStream.Position;
            foreach (var sig in validSigs)
            {
                fileStream.Position = 0;
                byte[] header = new byte[sig.Length];
                int read = fileStream.Read(header, 0, sig.Length);
                if (read == sig.Length && ByteArrayStartsWith(header, sig))
                {
                    fileStream.Position = originalPosition;
                    return true;
                }
            }
            fileStream.Position = originalPosition;
            return false;
        }

        private static bool ByteArrayStartsWith(byte[] header, byte[] sig)
        {
            if (header.Length < sig.Length)
            {
                return false;
            }
            for (int i = 0; i < sig.Length; i++)
            {
                if (header[i] != sig[i])
                {
                    return false;
                }
            }
            return true;
        }
    }
}

