using System;
using System.IO;
using System.Text.RegularExpressions;
using System.Collections.Generic;

namespace FileUpload.Models
{
    public static class FileNameHelper
    {
        private static readonly Regex FileNameRegex = new Regex(@"^[a-zA-Z0-9_\-\.]{1,100}$", RegexOptions.Compiled);
        private static readonly Dictionary<string, string> AllowedExtensions = new Dictionary<string, string>
        {
            { ".jpg",  null },
            { ".jpeg", null },
            { ".png",  null },
            { ".pdf",  null },
            { ".docx", null }
        };

        public static string GenerateSafeFileName(string originalFileName, string[] allowedExtensions)
        {
            if (string.IsNullOrWhiteSpace(originalFileName))
            {
                return null;
            }

            string decodedFileName = Path.GetFileName(Uri.UnescapeDataString(originalFileName));
            if (decodedFileName.Length > 100)
            {
                decodedFileName = decodedFileName.Substring(0, 100);
            }

            if (!FileNameRegex.IsMatch(decodedFileName))
            {
                return null;
            }

            string extension = Path.GetExtension(decodedFileName).ToLowerInvariant();

            if (!AllowedExtensions.ContainsKey(extension))
            {
                return null;
            }

            string safeExt = AllowedExtensions[extension];
            string uniqueId = Guid.NewGuid().ToString("N");
            return $"{uniqueId}{safeExt}";
        }
    }
}

