        private readonly string _uploadDirectory;
        private readonly ILogger<FileStorageService> _logger;

        public FileStorageService(IConfiguration configuration, ILogger<FileStorageService> logger)
        {
            _uploadDirectory = configuration.GetValue<string>("FileUpload:UploadDirectory", Path.Combine(AppContext.BaseDirectory, "uploads"));
            _logger = logger;
        }

        public async Task<string> SaveFileAsync(string fileName, Stream fileStream, long maxFileSize, CancellationToken cancellationToken)
        {
            if (fileName == null)
            {
                throw new ArgumentException("FileName is null");
            }

            if (fileStream == null)
            {
                throw new ArgumentException("Stream is null");
            }

            if (maxFileSize < 1)
            {
                throw new ArgumentException("MaxFileSize is invalid");
            }

            Directory.CreateDirectory(_uploadDirectory);

            string safeFileName = Path.GetFileName(fileName);

            string filePath = Path.Combine(_uploadDirectory, safeFileName);

            if (File.Exists(filePath))
            {
                throw new IOException("File already exists");
            }

            using (var fs = new FileStream(filePath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, true))
            {
                long totalBytesRead = 0;
                byte[] buffer = new byte[81920];
                int bytesRead;

                while ((bytesRead = await fileStream.ReadAsync(buffer, 0, buffer.Length, cancellationToken).ConfigureAwait(false)) > 0)
                {
                    totalBytesRead += bytesRead;
                    if (totalBytesRead > maxFileSize)
                    {
                        _logger.LogWarning("File exceeds maximum allowed size.");
                        File.Delete(filePath);
                        throw new IOException("File exceeds maximum allowed size.");
                    }
                    await fs.WriteAsync(buffer, 0, bytesRead, cancellationToken).ConfigureAwait(false);
                }
            }

            // Set least privilege permissions (platform-dependent, omitted for brevity)
            return filePath;
        }
    }
}

