using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Configuration;
using System;
using System.IO;
using System.Threading.Tasks;
using System.Linq;
using System.Collections.Generic;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading;
using System.Text.RegularExpressions;

namespace FileUpload.Controllers
{
    // Policy setup: In Startup/Program, add a policy named "FileUploadPolicy" with required claims/roles.
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "FileUploadPolicy")]
    public class FileUploadController : ControllerBase
    {
        private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            ".jpg", ".jpeg", ".png", ".pdf", ".docx"
        };

        private static readonly Dictionary<string, byte[]> FileSignatures = new Dictionary<string, byte[]>
        {
            { ".jpg", new byte[] { 0xFF, 0xD8, 0xFF } },
            { ".jpeg", new byte[] { 0xFF, 0xD8, 0xFF } },
            { ".png", new byte[] { 0x89, 0x50, 0x4E, 0x47 } },
            { ".pdf", new byte[] { 0x25, 0x50, 0x44, 0x46 } },
            { ".docx", new byte[] { 0x50, 0x4B, 0x03, 0x04 } }
        };

        private const long MaxFileSize = 10 * 1024 * 1024; // 10 MB
        private static readonly Regex SafeFilenameRegex = new Regex(@"^[a-zA-Z0-9_\-\.]{1,100}$", RegexOptions.Compiled);

        private readonly ILogger<FileUploadController> _logger;
        private readonly IHttpClientFactory _httpClientFactory;
        private readonly IConfiguration _configuration;

        public FileUploadController(ILogger<FileUploadController> logger, IHttpClientFactory httpClientFactory, IConfiguration configuration)
        {
            _logger = logger;
            _httpClientFactory = httpClientFactory;
            _configuration = configuration;
        }

        [HttpPost("upload")]
        [Authorize(Policy = "FileUploadPolicy")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> UploadFileAsync([FromForm] FileUploadRequestDto request, CancellationToken cancellationToken)
        {
            try
            {
                if (!ModelState.IsValid)
                {
                    return BadRequest(new { error = "Invalid file upload request." });
                }

                var file = request.File;
                if (file == null || file.Length == 0)
                {
                    return BadRequest(new { error = "No file provided." });
                }

                if (file.Length > MaxFileSize)
                {
                    return BadRequest(new { error = "File size exceeds the allowed limit." });
                }

                var originalFileName = Path.GetFileName(file.FileName);
                if (!SafeFilenameRegex.IsMatch(originalFileName))
                {
                    return BadRequest(new { error = "Invalid filename." });
                }

                var fileExtension = Path.GetExtension(originalFileName);
                if (!AllowedExtensions.Contains(fileExtension))
                {
                    return BadRequest(new { error = "File type not allowed." });
                }

                // Check file signature
                if (!await FileSignatureValidator.HasValidSignatureAsync(file, fileExtension, cancellationToken))
                {
                    return BadRequest(new { error = "File content does not match its extension." });
                }

                // Generate a safe server-side filename
                var safeFileName = $"{Guid.NewGuid():N}{fileExtension}";

                // Store files outside web root
                var uploadBasePath = _configuration.GetValue<string>("FileUpload:SafeBasePath") ?? Path.Combine(AppContext.BaseDirectory, "App_Data", "Uploads");
                Directory.CreateDirectory(uploadBasePath);

                var savePath = Path.Combine(uploadBasePath, safeFileName);

                // Prevent path traversal
                if (!savePath.StartsWith(uploadBasePath, StringComparison.Ordinal))
                {
                    return BadRequest(new { error = "Invalid file path." });
                }

                using (var stream = new FileStream(savePath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, true))
                {
                    await file.CopyToAsync(stream, cancellationToken);
                }

                // Optional: Scan file here before making it available

                // Return only a download handler URL, not direct link
                var downloadUrl = Url.Action("Download", "FileUpload", new { fileId = safeFileName }, Request.Scheme);

                _logger.LogInformation("File uploaded: {SafeFileName}, Size: {FileSize}", safeFileName, file.Length);

                return Ok(new { downloadUrl, safeFileName });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error during file upload.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        [HttpGet("download")]
        [Authorize(Policy = "FileUploadPolicy")]
        public IActionResult Download([FromQuery] string fileId)
        {
            if (string.IsNullOrWhiteSpace(fileId) || !SafeFilenameRegex.IsMatch(fileId))
            {
                return NotFound();
            }

            var uploadBasePath = _configuration.GetValue<string>("FileUpload:SafeBasePath") ?? Path.Combine(AppContext.BaseDirectory, "App_Data", "Uploads");
            var fullPath = Path.Combine(uploadBasePath, fileId);

            if (!File.Exists(fullPath))
            {
                return NotFound();
            }

            var extension = Path.GetExtension(fileId).ToLowerInvariant();

            var contentType = FileUploadContentTypes.GetContentType(extension);

            var stream = new FileStream(fullPath, FileMode.Open, FileAccess.Read, FileShare.Read, 4096, true);

            return File(stream, contentType, fileId);
        }
    }
}

