// Utils/FileSignatureValidator.cs
using Microsoft.AspNetCore.Http;
using System.IO;
using System.Threading;
using System.Threading.Tasks;
using System.Collections.Generic;

namespace FileUpload
{
    public static class FileSignatureValidator
    {
        private static readonly Dictionary<string, int[]> FileSignatures = new Dictionary<string, int[]>
        {
            { ".jpg", new int[] { 0xFF, 0xD8, 0xFF } },
            { ".jpeg", new int[] { 0xFF, 0xD8, 0xFF } },
            { ".png", new int[] { 0x89, 0x50, 0x4E, 0x47 } },
            { ".pdf", new int[] { 0x25, 0x50, 0x44, 0x46 } },
            { ".docx", new int[] { 0x50, 0x4B, 0x03, 0x04 } }
        };

        public static async Task<bool> HasValidSignatureAsync(IFormFile file, string extension, CancellationToken cancellationToken)
        {
            if (!FileSignatures.TryGetValue(extension, out var expectedSignature))
            {
                return false;
            }

            byte[] buffer = new byte[expectedSignature.Length];
            using (var stream = file.OpenReadStream())
            {
                int bytesRead = await stream.ReadAsync(buffer, 0, buffer.Length, cancellationToken);
                if (bytesRead != buffer.Length)
                {
                    return false;
                }
            }

            for (int i = 0; i < expectedSignature.Length; i++)
            {
                if (buffer[i] != expectedSignature[i])
                {
                    return false;
                }
            }
            return true;
        }
    }
}

// Utils/FileUploadContentTypes.cs
using System.Collections.Generic;

namespace FileUpload
{
    public static class FileUploadContentTypes
    {
        private static readonly Dictionary<string, string> ContentTypes = new Dictionary<string, string>
        {
            { ".jpg", "image/jpeg" },
            { ".jpeg", "image/jpeg" },
            { ".png", "image/png" },
            { ".pdf", "application/pdf" },
            { ".docx", "application/vnd.openxmlformats-officedocument.wordprocessingml.document" }
        };

        public static string GetContentType(string extension)
        {
            if (ContentTypes.TryGetValue(extension, out var contentType))
            {
                return contentType;
            }
            return "application/octet-stream";
        }
    }
}

