using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace WebhookService.Controllers
{
    // Policy setup: Add policy "WebhookFetch" in your authorization configuration.
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "WebhookFetch")]
    public class WebhookController : ControllerBase
    {
        private static readonly HashSet<string> AllowedDomains = new(StringComparer.OrdinalIgnoreCase)
        {
            // Add allowed domains here (example):
            "example.com",
            "api.example.com"
        };

        private static readonly HashSet<string> AllowedSchemes = new(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly IConfiguration _configuration;

        public WebhookController(
            IHttpClientFactory httpClientFactory,
            ILogger<WebhookController> logger,
            IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("fetch")]
        [Authorize(Policy = "WebhookFetch")]
        public async Task<IActionResult> FetchContentAsync([FromBody] WebhookFetchRequestDto request)
        {
            try
            {
                if (request == null || string.IsNullOrWhiteSpace(request.Url))
                {
                    return BadRequest(new { error = "URL is required." });
                }

                if (!TryValidateAndCanonicalizeUrl(request.Url, out var validatedUri, out var error))
                {
                    _logger.LogWarning("Webhook fetch SSRF validation failed: {Error}", error);
                    return BadRequest(new { error });
                }

                var client = _httpClientFactory.CreateClient("WebhookSafeClient");
                client.Timeout = TimeSpan.FromSeconds(10);

                var httpRequest = new HttpRequestMessage(HttpMethod.Get, validatedUri);

                var response = await client.SendAsync(httpRequest, HttpCompletionOption.ResponseHeadersRead, HttpContext.RequestAborted);

                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Webhook fetch failed for URL {Url} with status {Status}", validatedUri, response.StatusCode);
                    return StatusCode((int)response.StatusCode, new { error = "Failed to fetch content." });
                }

                var content = await response.Content.ReadAsStringAsync();
                _logger.LogInformation("Webhook fetch succeeded for URL {Url}", validatedUri);
                return Ok(content);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error during webhook fetch.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private bool TryValidateAndCanonicalizeUrl(string inputUrl, out Uri validatedUri, out string error)
        {
            validatedUri = null;
            error = null;

            if (!Uri.TryCreate(inputUrl, UriKind.Absolute, out var uri))
            {
                error = "Invalid URL format.";
                return false;
            }

            if (!AllowedSchemes.Contains(uri.Scheme))
            {
                error = "Scheme not allowed.";
                return false;
            }

            // Host allowlist check
            var host = uri.Host.TrimEnd('.').ToLowerInvariant();
            if (!AllowedDomains.Contains(host))
            {
                error = "Domain not allowed.";
                return false;
            }

            // DNS resolution and IP checks
            try
            {
                var addresses = Dns.GetHostAddresses(host);
                foreach (var ip in addresses)
                {
                    if (IsPrivateOrLocalIp(ip))
                    {
                        error = "Target resolves to a private or local IP.";
                        return false;
                    }
                }
            }
            catch
            {
                error = "Failed to resolve host.";
                return false;
            }

            validatedUri = uri;
            return true;
        }

        private static bool IsPrivateOrLocalIp(IPAddress ip)
        {
            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 127.0.0.0/8
                if (bytes[0] == 127)
                {
                    return true;
                }
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
            }
            if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo)
                {
                    return true;
                }
                if (IPAddress.IsLoopback(ip))
                {
                    return true;
                }
            }
            if (IPAddress.IsLoopback(ip))
            {
                return true;
            }
            // Check for special Reserved IPs (RFC 1918, 4.7)
            return false;
        }
    }

