using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Configuration;
using System.Net.Http;
using System.Threading.Tasks;
using System;
using System.Linq;
using System.Net;
using System.Text.RegularExpressions;
using System.Collections.Generic;

// Policy setup required in Program.cs or Startup.cs:
// services.AddAuthorization(options => { options.AddPolicy("UrlPreviewPolicy", policy => policy.RequireAuthenticatedUser()); });

namespace UrlPreview.Controllers
{
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "UrlPreviewPolicy")]
    public class UrlPreviewController : ControllerBase
    {
        private static readonly HashSet<string> AllowedDomains = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            // Add only business-required allowed domains here
            "example.com",
            "www.example.com"
        };

        private static readonly HashSet<string> AllowedSchemes = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<UrlPreviewController> _logger;
        private readonly IConfiguration _configuration;

        public UrlPreviewController(IHttpClientFactory httpClientFactory, ILogger<UrlPreviewController> logger, IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("preview")]
        [Authorize(Policy = "UrlPreviewPolicy")]
        public async Task<IActionResult> PreviewUrl([FromBody] UrlPreviewRequestDto request)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(new { error = "Invalid input." });
            }

            try
            {
                var uri = ValidateAndCanonicalizeUrl(request.Url);

                if (!AllowedSchemes.Contains(uri.Scheme))
                {
                    _logger.LogWarning("Rejected URL with disallowed scheme: {Scheme}", uri.Scheme);
                    return BadRequest(new { error = "URL scheme not allowed." });
                }

                var host = uri.Host.TrimEnd('.').ToLowerInvariant();

                if (!AllowedDomains.Contains(host))
                {
                    _logger.LogWarning("Rejected URL with disallowed host: {Host}", host);
                    return BadRequest(new { error = "Host not allowed." });
                }

                var ipAddresses = await Dns.GetHostAddressesAsync(host);
                if (ipAddresses.Length == 0 || ipAddresses.Any(ip => !IsPublicIpAddress(ip)))
                {
                    _logger.LogWarning("Rejected URL with private or disallowed IP: {Host}", host);
                    return BadRequest(new { error = "Host not allowed." });
                }

                using var httpClient = _httpClientFactory.CreateClient();
                httpClient.Timeout = TimeSpan.FromSeconds(_configuration.GetValue<int?>("UrlPreview:TimeoutSeconds") ?? 5);
                httpClient.DefaultRequestHeaders.Clear();
                httpClient.MaxResponseContentBufferSize = 1024 * 1024; // 1MB

                using var requestMessage = new HttpRequestMessage(HttpMethod.Get, uri);
                requestMessage.RequestUri = uri;

                using var response = await httpClient.SendAsync(requestMessage, HttpCompletionOption.ResponseHeadersRead, HttpContext.RequestAborted);

                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("PreviewUrl: Non-success status code {StatusCode} for {Url}", response.StatusCode, request.Url);
                    return BadRequest(new { error = "Failed to fetch url preview." });
                }

                var contentType = response.Content.Headers.ContentType?.MediaType ?? "";
                if (!contentType.StartsWith("text/html", StringComparison.OrdinalIgnoreCase))
                {
                    _logger.LogWarning("PreviewUrl: Non-HTML content type {ContentType} for {Url}", contentType, request.Url);
                    return BadRequest(new { error = "URL is not an HTML page." });
                }

                var content = await response.Content.ReadAsStringAsync();

                return Ok(new UrlPreviewResponseDto { Preview = content });
            }
            catch (UriFormatException)
            {
                return BadRequest(new { error = "Malformed URL." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error fetching URL preview.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private static Uri ValidateAndCanonicalizeUrl(string url)
        {
            var uri = new Uri(url, UriKind.Absolute);

            // Prevent SSRF: block localhost, loopback, private, link-local, etc.
            var host = uri.Host.TrimEnd('.').ToLowerInvariant();
            var addresses = Dns.GetHostAddresses(host);

            foreach (var ip in addresses)
            {
                if (!IsPublicIpAddress(ip))
                {
                    throw new UriFormatException("URL points to a non-public IP address.");
                }
            }

            // Prevent redirects to internal/untrusted domains
            if (IsDomainAllowed(host) == false)
            {
                throw new UriFormatException("Host is not allowlisted.");
            }

            return uri;
        }

        private static bool IsPublicIpAddress(IPAddress ip)
        {
            if (IPAddress.IsLoopback(ip))
            {
                return false;
            }

            if (ip.AddressFamily == System.Net.Sockets.AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return false;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return false;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return false;
                }
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return false;
                }
                // 127.0.0.0/8 (loopback)
                if (bytes[0] == 127)
                {
                    return false;
                }
            }
            else if (ip.AddressFamily == System.Net.Sockets.AddressFamily.InterNetworkV6)
            {
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo || ip.IsIPv6UniqueLocal)
                {
                    return false;
                }
                if (ip.Equals(IPAddress.IPv6Loopback))
                {
                    return false;
                }
            }
            return true;
        }

        private static bool IsDomainAllowed(string host)
        {
            // Only allow exact matches (no subdomains)
            return AllowedDomains.Contains(host);
        }
    }
}

