            if (requestDto == null || !ModelState.IsValid)
            {
                _logger.LogWarning("Invalid webhook request.");
                return BadRequest(new { error = "Invalid request." });
            }

            try
            {
                var url = CanonicalizeAndValidateUrl(requestDto.CallbackUrl);
                if (url == null)
                {
                    _logger.LogWarning("URL validation failed: {CallbackUrl}", requestDto.CallbackUrl);
                    return BadRequest(new { error = "Invalid or disallowed callback URL." });
                }

                // Only allow HTTPS
                if (!AllowedSchemes.Contains(url.Scheme))
                {
                    _logger.LogWarning("Rejected non-HTTPS scheme: {Scheme}", url.Scheme);
                    return BadRequest(new { error = "Only HTTPS scheme is allowed." });
                }

                // Check host allowlist
                var host = url.Host.TrimEnd('.').ToLowerInvariant();
                if (!AllowedDomains.Contains(host))
                {
                    _logger.LogWarning("Rejected host not in allowlist: {Host}", host);
                    return BadRequest(new { error = "Host not allowed." });
                }

                // Prevent SSRF by resolving and validating IPs
                var ipAddresses = await Dns.GetHostAddressesAsync(host);
                foreach (var ip in ipAddresses)
                {
                    if (IsPrivateOrLocalIp(ip))
                    {
                        _logger.LogWarning("Rejected private or local IP: {IP}", ip);
                        return BadRequest(new { error = "Target address is not allowed." });
                    }
                }

                var client = _httpClientFactory.CreateClient("WebhookSafeClient");
                client.Timeout = TimeSpan.FromSeconds(10);

                var request = new HttpRequestMessage(HttpMethod.Post, url)
                {
                    Content = new StringContent(requestDto.Payload ?? string.Empty)
                };

                var response = await client.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);
                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Webhook callback failed: {StatusCode} {ReasonPhrase}", response.StatusCode, response.ReasonPhrase);
                    return StatusCode((int)HttpStatusCode.BadGateway, new { error = "Failed to call callback." });
                }

                return Ok();
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error in webhook POST.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private static Uri CanonicalizeAndValidateUrl(string url)
        {
            if (string.IsNullOrWhiteSpace(url))
            {
                return null;
            }

            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri))
            {
                return null;
            }

            // Only allow safe path components
            var safePath = Uri.UnescapeDataString(uri.GetPath()).Replace('\\', '/');
            if (safePath.Contains("..") || safePath.StartsWith("/") || safePath.StartsWith("\\"))
            {
                return null;
            }

            // Enforce path length limit (defense in depth)
            if (safePath.Length > 2048)
            {
                return null;
            }

            // Only allow safe scheme
            if (!AllowedSchemes.Contains(uri.Scheme))
            {
                return null;
            }

            // Only allow safe ports
            if (uri.Port != 443 && uri.Port != -1)
            {
                return null;
            }

            // Only allow safe schemes
            if (!IsSafeScheme(uri.Scheme))
            {
                return null;
            }

            // Only allow valid public host
            if (!IsValidHost(uri.Host))
            {
                return null;
            }

            return new UriBuilder(uri.Scheme, uri.Host, uri.Port, safePath, uri.Query).Uri;
        }

        private static bool IsSafeScheme(string scheme)
        {
            return scheme == "https";
        }

        private static bool IsValidHost(string host)
        {
            // Only allow FQDN or valid public domain names
            if (string.IsNullOrWhiteSpace(host))
            {
                return false;
            }

            if (host.Contains(' '))
            {
                return false;
            }

            if (host.Equals("localhost", StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            if (host.Equals("127.0.0.1", StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            if (IPAddress.TryParse(host, out var ip))
            {
                return !IsPrivateOrLocalIp(ip);
            }

            try
            {
                var addresses = Dns.GetHostAddresses(host);
                foreach (var ip in addresses)
                {
                    if (IsPrivateOrLocalIp(ip))
                    {
                        return false;
                    }
                }
            }
            catch
            {
                return false;
            }

            // Defense-in-depth: check for IPs in reserved ranges
            return IsPublicAddress(host);
        }

        private static bool IsPrivateOrLocalIp(IPAddress ip)
        {
            if (IPAddress.IsLoopback(ip))
            {
                return true;
            }

            if (ip.AddressFamily == System.Net.Sockets.AddressFamily.InterNetwork)
            {
                // IPv4
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
                // 127.0.0.0/8 (loopback)
                if (bytes[0] == 127)
                {
                    return true;
                }
            }
            else if (ip.AddressFamily == System.Net.Sockets.AddressFamily.InterNetworkV6)
            {
                // IPv6
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo)
                {
                    return true;
                }
                if (ip.Equals(IPAddress.IPv6Loopback))
                {
                    return true;
                }
                if (ip.Equals(IPAddress.IPv6None))
                {
                    return true;
                }
            }
            return false;
        }

        private static bool IsPublicAddress(string host)
        {
            try
            {
                var addresses = Dns.GetHostAddresses(host);
                foreach (var ip in addresses)
                {
                    // IPv4
                    if (ip.AddressFamily == System.Net.Sockets.AddressFamily.InterNetwork)
                    {
                        var bytes = ip.GetAddressBytes();
                        // 10.0.0.0/8
                        if (bytes[0] >= 10 && bytes[0] <= 135)
                        {
                            return false;
                        }
                        // 172.16.0.0/12
                        if (bytes[0] == 172 && (bytes[1] >= 16 && bytes[1] <= 31))
                        {
                            return false;
                        }
                        // 192.168.0.0/16
                        if (bytes[0] == 192 && bytes[1] == 168)
                        {
                            return false;
                        }
                        // 169.254.0.0/16 (link-local)
                        if (bytes[0] == 169 && bytes[1] == 254)
                        {
                            return false;
                        }
                        // 127.0.0.0/8 (loopback)
                        if (bytes[0] == 127)
                        {
                            return false;
                        }
                        // 0.0.0.0/8 (unspecified)
                        if (bytes[0] == 0)
                        {
                            return false;
                        }
                        // 128.0.0.0/12 (multicast)
                        if (bytes[0] >= 128 && bytes[0] <= 135)
                        {
                            return false;
                        }
                    }
                    // IPv6
                    if (ip.AddressFamily == System.Net.Sockets.AddressFamily.InterNetworkV6)
                    {
                        if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo)
                        {
                            return false;
                        }
                        if (ip.Equals(IPAddress.IPv6Loopback))
                        {
                            return false;
                        }
                        if (ip.Equals(IPAddress.IPv6None))
                        {
                            return false;
                        }
                    }
                }
            }
            catch
            {
                return false;
            }
            return true;
        }
    }
}

