// Policy setup required in Startup/Program.cs:
// options.AddPolicy("UrlPreviewPolicy", policy => policy.RequireAuthenticatedUser());

namespace UrlPreview.Controllers
{
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "UrlPreviewPolicy")]
    public class UrlPreviewController : ControllerBase
    {
        private readonly IUrlPreviewService _urlPreviewService;
        private readonly ILogger<UrlPreviewController> _logger;

        public UrlPreviewController(IUrlPreviewService urlPreviewService, ILogger<UrlPreviewController> logger)
        {
            _urlPreviewService = urlPreviewService;
            _logger = logger;
        }

        [HttpPost]
        [Authorize(Policy = "UrlPreviewPolicy")]
        public async Task<IActionResult> Post([FromBody] UrlPreviewRequestDto request)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(new { error = "Invalid input." });
            }

            try
            {
                _logger.LogInformation("Url preview requested for inputUrl: {InputUrl}", request.Url);

                var preview = await _urlPreviewService.FetchUrlPreviewAsync(request.Url);

                if (preview == null)
                {
                    // Uniform error response for all permissions/validations
                    return NotFound(new { error = "Preview not available." });
                }

                return Ok(preview);
            }
            catch (UnauthorizedUrlException)
            {
                return Forbid();
            }
            catch (UrlPreviewValidationException ex)
            {
                _logger.LogWarning("Url preview validation failed: {Message}", ex.Message);
                return BadRequest(new { error = ex.Message });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error during url preview.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }
    }
}

