// Services/UrlPreviewService.cs
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net.Http;
using System.Threading.Tasks;
using UrlPreview.Models;
using System.Net;
using System.Text.RegularExpressions;

namespace UrlPreview.Services
{
    public class UrlPreviewService : IUrlPreviewService
    {
        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<UrlPreviewService> _logger;
        private readonly IConfiguration _configuration;
        private readonly HashSet<string> _allowedDomains;

        private static readonly HashSet<string> AllowedSchemes = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        public UrlPreviewService(
            IHttpClientFactory httpClientFactory,
            ILogger<UrlPreviewService> logger,
            IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
            _allowedDomains = _configuration.GetSection("UrlPreview:AllowedDomains").Get<HashSet<string>>() ?? new HashSet<string>();
        }

        public async Task<UrlPreviewModel> FetchUrlPreviewAsync(string url)
        {
            var validatedUri = ValidateAndCanonicalizeUrl(url);

            if (!IsDomainAllowed(validatedUri.Host))
            {
                _logger.LogWarning("Rejected url with host: {Host}", validatedUri.Host);
                throw new UnauthorizedUrlException("Access to the specified host is not permitted.");
            }

            await ValidatePublicAddressAsync(validatedUri.Host);

            using var httpClient = _httpClientFactory.CreateClient();
            httpClient.Timeout = TimeSpan.FromSeconds(10);

            using var request = new HttpRequestMessage(HttpMethod.Get, validatedUri);
            request.Headers.UserAgent.ParseAdd("UrlPreviewBot/1.0");

            using var response = await httpClient.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);

            if (!response.IsSuccessStatusCode)
            {
                throw new UrlPreviewValidationException("Failed to retrieve remote resource.");
            }

            var contentType = response.Content.Headers.ContentType?.MediaType ?? "";
            if (!contentType.Contains("html"))
            {
                throw new UrlPreviewValidationException("Content is not HTML.");
            }

            var html = await response.Content.ReadAsStringAsync();
            var preview = ExtractPreviewFromHtml(html, validatedUri.ToString());
            return preview;
        }

        private static Uri ValidateAndCanonicalizeUrl(string url)
        {
            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri))
            {
                throw new UrlPreviewValidationException("Invalid URL format.");
            }

            if (!AllowedSchemes.Contains(uri.Scheme))
            {
                throw new UrlPreviewValidationException("Only HTTPS URLs are allowed.");
            }

            if (!Regex.IsMatch(uri.Host, @"^[a-zA-Z0-9\-\.]+$"))
            {
                throw new UrlPreviewValidationException("Invalid host format.");
            }

            if (uri.Host.Length > 253)
            {
                throw new UrlPreviewValidationException("Host too long.");
            }

            return uri;
        }

        private bool IsDomainAllowed(string host)
        {
            // Only allow whitelisted domains, never allow arbitrary hosts
            foreach (var allowed in _allowedDomains)
            {
                if (host.Equals(allowed, StringComparison.OrdinalIgnoreCase))
                {
                    return true;
                }
            }
            return false;
        }

        private async Task ValidatePublicAddressAsync(string host)
        {
            try
            {
                var addresses = await Dns.GetHostAddressesAsync(host);
                foreach (var addr in addresses)
                {
                    if (IsPrivateOrLocalIp(addr))
                    {
                        throw new UrlPreviewValidationException("Access to internal or private addresses is not allowed.");
                    }
                }
            }
            catch
            {
                throw new UrlPreviewValidationException("Could not resolve host.");
            }
        }

        private static bool IsPrivateOrLocalIp(IPAddress ip)
        {
            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10) return true;
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31) return true;
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168) return true;
                // 127.0.0.0/8 (loopback)
                if (bytes[0] == 127) return true;
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254) return true;
            }
            else if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo)
                {
                    return true;
                }
                if (ip.Equals(IPAddress.IPv6Loopback)) return true;
                if (ip.Equals(IPAddress.IPv6None)) return true;
            }
            return false;
        }

        private static UrlPreviewModel ExtractPreviewFromHtml(string html, string url)
        {
            // Minimal HTML title and meta description extraction
            var title = null as string;
            var description = null as string;
            var image = null as string;

            var titleMatch = Regex.Match(html, "<title>(.*?)</title>", RegexOptions.IgnoreCase | RegexOptions.Singleline);
            if (titleMatch.Success)
            {
                title = titleMatch.Groups[1].Value.Trim();
            }

            var metaDescriptionMatch = Regex.Match(html, "<meta[^>]+name=[\"']description[\"'][^>]+content=[\"'](.*?)[\"'][^>]*>", RegexOptions.IgnoreCase | RegexOptions.Singleline);
            if (metaDescriptionMatch.Success)
            {
                description = metaDescriptionMatch.Groups[1].Value.Trim();
            }

            var metaImageMatch = Regex.Match(html, "<meta[^>]+property=[\"']og:image[\"'][^>]+content=[\"'](.*?)[\"'][^>]*>", RegexOptions.IgnoreCase | RegexOptions.Singleline);
            if (metaImageMatch.Success)
            {
                image = metaImageMatch.Groups[1].Value.Trim();
            }

            return new UrlPreviewModel
            {
                Title = title,
                Description = description,
                ImageUrl = image,
                Url = url
            };
        }
    }
}

