// Controllers/WebhookController.cs
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace WebhookApi.Controllers
{
    // Policy setup: services.AddAuthorization(options => options.AddPolicy("WebhookAdmin", policy => policy.RequireRole("WebhookAdmin")));
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "WebhookAdmin")]
    public class WebhookController : ControllerBase
    {
        private static readonly HashSet<string> AllowlistDomains = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "example.com",
            "hooks.example.org"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly IConfiguration _configuration;

        public WebhookController(IHttpClientFactory httpClientFactory, ILogger<WebhookController> logger, IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("{id}")]
        [Authorize(Policy = "WebhookAdmin")]
        public async Task<IActionResult> InvokeWebhook(string id)
        {
            try
            {
                var webhookUrl = _configuration.GetValue<string>($"Webhook:Url:{id}");
                if (string.IsNullOrWhiteSpace(webhookUrl))
                {
                    _logger.LogWarning("Webhook {Id} not found in configuration", id);
                    return NotFound();
                }

                if (!TryValidateAndCanonicalizeUrl(webhookUrl, out var validatedUri, out var error))
                {
                    _logger.LogWarning("Webhook {Id} validation failed: {Error}", id, error);
                    return BadRequest(new { error });
                }

                if (!AllowlistDomains.Contains(validatedUri.Host))
                {
                    _logger.LogWarning("Webhook {Id} host {Host} is not in allowlist", id, validatedUri.Host);
                    return BadRequest(new { error = "Destination not allowed." });
                }

                using var client = _httpClientFactory.CreateClient();
                client.Timeout = TimeSpan.FromSeconds(10);
                client.DefaultRequestHeaders.Clear();

                var request = new HttpRequestMessage(HttpMethod.Post, validatedUri)
                {
                    Version = HttpVersion.Version20
                };

                var result = await client.SendAsync(request, HttpCompletionOption.ResponseHeadersRead, HttpContext.RequestAborted);

                if (!result.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Webhook {Id} returned status {StatusCode}", id, result.StatusCode);
                    return StatusCode((int)result.StatusCode, new { error = "Webhook call failed." });
                }

                _logger.LogInformation("Invoked webhook {Id} successfully", id);
                return NoContent();
            }
            catch (TaskCanceledException)
            {
                _logger.LogWarning("Webhook {Id} timed out", id);
                return BadRequest(new { error = "Timeout while invoking webhook." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error invoking webhook {Id}", id);
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private static bool TryValidateAndCanonicalizeUrl(string url, out Uri validatedUri, out string error)
        {
            validatedUri = null;
            error = null;

            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri))
            {
                error = "Invalid URL format.";
                return false;
            }

            if (!string.Equals(uri.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase))
            {
                error = "Only HTTPS scheme is allowed.";
                return false;
            }

            if (!IsHostSafe(uri.Host, out error))
            {
                return false;
            }

            validatedUri = new UriBuilder(uri.Scheme, uri.Host, uri.Port, uri.AbsolutePath, uri.Query).Uri;
            return true;
        }

        private static bool IsHostSafe(string host, out string error)
        {
            error = null;

            if (string.IsNullOrWhiteSpace(host))
            {
                error = "Missing host.";
                return false;
            }

            if (host.IndexOfAny(Path.GetInvalidHostChars()) >= 0)
            {
                error = "Host contains invalid characters.";
                return false;
            }

            if (IPAddress.TryParse(host, out var ip))
            {
                if (IsIpUnsafe(ip))
                {
                    error = "Unsafe IP address.");
                    return false;
                }
            }
            else
            {
                try
                {
                    var addresses = Dns.GetHostAddresses(host);
                    if (addresses.Any(IsIpUnsafe))
                    {
                        error = "Resolved IP is unsafe.";
                        return false;
                    }
                }
                catch
                {
                    error = "Could not resolve host.";
                    return false;
                }
            }
            return true;
        }

        private static bool IsIpUnsafe(IPAddress ip)
        {
            if (IPAddress.IsLoopback(ip))
            {
                return true;
            }

            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 127.0.0.0/8
                if (bytes[0] == 127)
                {
                    return true;
                }
                // Link-local 169.254.0.0/16
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
            }
            else if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo)
                {
                    return true;
                }
                if (ip.Equals(IPAddress.IPv6Loopback))
                {
                    return true;
                }
                if (ip.Equals(IPAddress.IPv6None))
                {
                    return true;
                }
            }
            return false;
        }
    }
}

