using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using System.Net.Http;
using System.Threading.Tasks;
using System.Text.RegularExpressions;
using System;
using System.Linq;
using System.Collections.Generic;
using System.Net;
using System.Net.Sockets;

namespace MyApp.Controllers
{
    // Set up the policy in Program.cs or Startup.cs:
    // services.AddAuthorization(options => { options.AddPolicy("UrlPreviewPolicy", policy => policy.RequireAuthenticatedUser()); });
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "UrlPreviewPolicy")]
    public class UrlPreviewController : ControllerBase
    {
        private static readonly HashSet<string> AllowedDomains = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "example.com",
            "www.example.com"
            // Add more allowed domains as needed
        };

        private static readonly HashSet<string> AllowedSchemes = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<UrlPreviewController> _logger;

        public UrlPreviewController(IHttpClientFactory httpClientFactory, ILogger<UrlPreviewController> logger)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
        }

        [HttpPost("preview")]
        [Authorize(Policy = "UrlPreviewPolicy")]
        public async Task<IActionResult> GetUrlPreview([FromBody] UrlPreviewRequestDto request)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(new { error = "Invalid input." });
            }

            try
            {
                var uri = CanonicalizeAndValidateUrl(request.UserEnteredUrl);

                using var httpClient = _httpClientFactory.CreateClient(nameof(UrlPreviewController));
                httpClient.Timeout = TimeSpan.FromSeconds(5);
                httpClient.DefaultRequestHeaders.Clear();
                httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("Mozilla/5.0 (compatible; UrlPreviewBot/1.0)");

                using var httpRequest = new HttpRequestMessage(HttpMethod.Get, uri);
                using var response = await httpClient.SendAsync(httpRequest, HttpCompletionOption.ResponseHeadersRead, HttpContext.RequestAborted);

                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Failed to preview URL {Url} with status {StatusCode}", uri, response.StatusCode);
                    return StatusCode((int)response.StatusCode, new { error = "Unable to fetch preview." });
                }

                var content = await response.Content.ReadAsStringAsync(HttpContext.RequestAborted);
                var preview = new UrlPreviewDto
                {
                    Content = content,
                    Url = uri.ToString()
                };

                _logger.LogInformation("Previewed URL {Url} successfully.", uri);

                return Ok(preview);
            }
            catch (UrlValidationException ex)
            {
                _logger.LogWarning("Invalid URL validation: {Message}", ex.Message);
                return BadRequest(new { error = ex.Message });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error while previewing URL.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private static Uri CanonicalizeAndValidateUrl(string userEnteredUrl)
        {
            if (string.IsNullOrWhiteSpace(userEnteredUrl))
            {
                throw new UrlValidationException("URL is required.");
            }

            if (!Uri.TryCreate(userEnteredUrl, UriKind.Absolute, out var uri))
            {
                throw new UrlValidationException("Invalid URL format.");
            }

            if (!AllowedSchemes.Contains(uri.Scheme))
            {
                throw new UrlValidationException("Only HTTPS URLs are allowed.");
            }

            var host = uri.Host.TrimEnd('.').ToLowerInvariant();

            if (!AllowedDomains.Contains(host))
            {
                throw new UrlValidationException("Domain is not allowed.");
            }

            IPAddress[] addresses;
            try
            {
                addresses = Dns.GetHostAddresses(host);
            }
            catch
            {
                throw new UrlValidationException("Could not resolve host.");
            }

            foreach (var ip in addresses)
            {
                if (IsIpAddressUnsafe(ip))
                {
                    throw new UrlValidationException("Target address is not allowed.");
                }
            }

            return uri;
        }

        private static bool IsIpAddressUnsafe(IPAddress ip)
        {
            if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (IPAddress.IsLoopback(ip) || ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo)
                {
                    return true;
                }
            }
            else if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                if (bytes[0] == 10 ||
                    (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31) ||
                    (bytes[0] == 192 && bytes[1] == 168) ||
                    bytes[0] == 127 ||
                    bytes[0] >= 224) // multicast or reserved
                {
                    return true;
                }
            }
            return false;
        }
    }
}

