using System;
using System.Buffers.Text;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace WebhookService.Controllers
{
    // Setup: In Program.cs or Startup.cs, configure an authorization policy named "WebhookAccessPolicy"
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "WebhookAccessPolicy")]
    public class WebhookController : ControllerBase
    {
        private static readonly HashSet<string> AllowedHosts = new(StringComparer.OrdinalIgnoreCase)
        {
            // Add only business-required hosts/domains here
            "api.example.com",
            "hooks.example.org"
        };

        private static readonly HashSet<string> AllowedSchemes = new(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly IConfiguration _configuration;

        public WebhookController(IHttpClientFactory httpClientFactory, ILogger<WebhookController> logger, IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost]
        [Authorize(Policy = "WebhookAccessPolicy")]
        public async Task<IActionResult> PostAsync([FromBody] WebhookRequestDto requestDto)
        {
            try
            {
                if (requestDto == null || string.IsNullOrWhiteSpace(requestDto.Url))
                {
                    return BadRequest(new { error = "URL is required." });
                }

                if (!TryValidateAndCanonicalizeUrl(requestDto.Url, out var validatedUri, out var error))
                {
                    _logger.LogWarning("Webhook request validation failed: {Error}", error);
                    return BadRequest(new { error });
                }

                // Only allow HTTPS
                if (!AllowedSchemes.Contains(validatedUri.Scheme))
                {
                    _logger.LogWarning("Rejected non-HTTPS scheme: {Scheme}", validatedUri.Scheme);
                    return BadRequest(new { error = "Only HTTPS URLs are allowed." });
                }

                // Check host allowlist
                if (!AllowedHosts.Contains(validatedUri.Host))
                {
                    _logger.LogWarning("Rejected URL with host: {Host}", validatedUri.Host);
                    return BadRequest(new { error = "Target host is not allowed." });
                }

                // Resolve and check for private IPs
                if (!await IsHostPublicAsync(validatedUri.Host))
                {
                    _logger.LogWarning("Rejected URL due to private IP for host: {Host}", validatedUri.Host);
                    return BadRequest(new { error = "URL host resolves to a private or disallowed IP address." });
                }

                var client = _httpClientFactory.CreateClient(nameof(WebhookController));
                client.Timeout = TimeSpan.FromSeconds(_configuration.GetValue("Webhook:TimeoutSeconds", 10));
                client.DefaultRequestHeaders.Clear();

                var httpRequest = new HttpRequestMessage(HttpMethod.Post, validatedUri)
                {
                    Content = new StringContent(requestDto?.Data ?? string.Empty)
                };

                var response = await client.SendAsync(httpRequest, HttpCompletionOption.ResponseHeadersRead);

                switch (response.StatusCode)
                {
                    case HttpStatusCode.OK:
                    case HttpStatusCode.NoContent:
                    case HttpStatusCode.NonAuthoritativeInfo:
                        _logger.LogInformation("Webhook request to {Url} succeeded with status {Status}", validatedUri.ToString(), response.StatusCode);
                        return Ok();
                    default:
                        _logger.LogWarning("Webhook request to {Url} failed with status {Status}", validatedUri.ToString(), response.StatusCode);
                        return BadRequest(new { error = "Webhook request failed." });
                }
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Exception in webhook POST");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private static bool TryValidateAndCanonicalizeUrl(string url, out Uri validatedUri, out string error)
        {
            validatedUri = null;
            error = null;

            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri))
            {
                error = "Invalid URL format.";
                return false;
            }

            // Only allow known schemes
            if (!AllowedSchemes.Contains(uri.Scheme))
            {
                error = "Only HTTPS URLs are allowed.";
                return false;
            }

            // Disallow userinfo, fragments, etc.
            if (!string.IsNullOrEmpty(uri.UserInfo))
            {
                error = "URL must not include credentials.";
                return false;
            }

            // Canonicalize host
            var host = uri.Host.TrimEnd('.').ToLowerInvariant();

            // No IP literals, no localhost, no private/local addresses
            if (IPAddress.TryParse(host, out var ip))
            {
                if (!IPAddress.IsLoopback(ip) && !IsPublicIp(ip))
                {
                    error = "IP address is not allowed.";
                    return false;
                }
            }
            else
            {
                // DNS resolution and blocklist check
                List<IPAddress> addresses;
                try
                {
                    addresses = Dns.GetHostAddresses(host).Where(IsPublicIp).ToList();
                }
                catch
                {
                    error = "Could not resolve host.";
                    return false;
                }
                if (addresses.Count == 0)
                {
                    error = "No public addresses for host.";
                    return false;
                }
            }

            validatedUri = new UriBuilder(uri) { Host = host }.Uri;
            return true;
        }

        private static bool IsPublicIp(IPAddress ip)
        {
            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10) return false;
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31) return false;
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168) return false;
                // 127.0.0.0/8
                if (bytes[0] == 127) return false;
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254) return false;
                // 0.0.0.0/8
                if (bytes[0] == 0) return false;
                // 255.255.255.255 (broadcast)
                if (ip.Equals(IPAddress.Broadcast)) return false;
            }
            else if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo || ip.IsIPv6UniqueLocal)
                {
                    return false;
                }
                if (ip.Equals(IPAddress.IPv6Loopback) || ip.Equals(IPAddress.IPv6None))
                {
                    return false;
                }
            }
            return true;
        }

        private static async Task<bool> IsHostPublicAsync(string host)
        {
            try
            {
                var addresses = Dns.GetHostAddresses(host);
                foreach (var ip in addresses)
                {
                    if (!IsPublicIp(ip))
                    {
                        return false;
                    }
                }
                return true;
            }
            catch
            {
                return false;
            }
        }
    }
}

