using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;

public class FileUploadValidator
{
    private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
    {
        ".png", ".jpg", ".jpeg", ".gif", ".bmp", ".pdf", ".svg"
    };

    private static readonly Dictionary<string, byte[]> AllowedSignatures = new Dictionary<string, byte[]>
    {
        { ".png", new byte[] { 0x89, 0x50, 0x4E, 0x47 } }, // PNG
        { ".jpg", new byte[] { 0xFF, 0xD8, 0xFF } }, // JPEG
        { ".jpeg", new byte[] { 0xFF, 0xD8, 0xFF } },
        { ".gif", new byte[] { 0x47, 0x49, 0x46, 0x38 } }, // GIF
        { ".pdf", new byte[] { 0x25, 0x50, 0x44, 0x46 } }, // PDF
        { ".svg", new byte[] { 0x3C, 0x73, 0x76, 0x67 } }, // SVG (start of SVG: '<svg')
    };

    public bool IsFileValid(Stream fileStream, out string error)
    {
        error = null;
        if (fileStream == null)
        {
            error = "No file uploaded.";
            return false;
        }
        long originalPosition = fileStream.Position;
        long fileSize = fileStream.Length;
        if (fileSize == 0 || fileSize > 5 * 1024 * 1024) // 5 MB limit
        {
            error = "File size is invalid.";
            return false;
        }
        string extension = Path.GetExtension(fileStream.FileName);
        if (string.IsNullOrWhiteSpace(extension) || !AllowedExtensions.Contains(extension))
        {
            error = "File extension is not allowed.";
            return false;
        }
        if (!AllowedSignatures.ContainsKey(extension))
        {
            error = "File type is not allowed.";
            return false;
        }
        byte[] expectedSignature = AllowedSignatures[extension];
        int signatureLength = expectedSignature.Length;
        byte[] buffer = new byte[signatureLength];
        int bytesRead = fileStream.Read(buffer, 0, signatureLength);
        if (bytesRead != signatureLength)
        {
            error = "File is too small for its type.";
            return false;
        }
        for (int i = 0; i < signatureLength; i++)
        {
            if (buffer[i] != expectedSignature[i])
            {
                error = "File signature does not match file type.";
                return false;
            }
        }
        fileStream.Position = originalPosition;
        return true;
    }
}

[HttpPost("api/files/{folderName}/{fileName}")]
public IActionResult UploadFile(string folderName, string fileName)
{
    if (!ModelState.IsValid)
    {
        return BadRequest(new { error = "Invalid model state." });
    }

    try
    {
        var file = Request.Form.Files["file"];
        if (file == null)
        {
            return BadRequest(new { error = "No file uploaded." });
        }

        var safeFolderName = Path.GetFileName(folderName);
        var safeFileName = Path.GetFileName(fileName);
        if (string.IsNullOrWhiteSpace(safeFolderName) || string.IsNullOrWhiteSpace(safeFileName))
        {
            return BadRequest(new { error = "Invalid folder or file name." });
        }

        if (!FileNameValidator.IsValid(safeFileName))
        {
            return BadRequest(new { error = "Invalid file name." });
        }

        if (file.Length == 0 || file.Length > 5 * 1024 * 1024)
        {
            return BadRequest(new { error = "File size is invalid." });
        }

        var extension = Path.GetExtension(safeFileName);
        if (!FileUploadValidator.AllowedExtensions.Contains(extension))
        {
            return BadRequest(new { error = "File extension is not allowed." });
        }

        // Store files outside web root, e.g.: Files/uploads/{safeFolderName}/{safeFileName}
        string baseUploadPath = Path.Combine(AppContext.BaseDirectory, "Files", "uploads");
        if (!Directory.Exists(baseUploadPath))
        {
            Directory.CreateDirectory(baseUploadPath);
        }

        string destinationPath = Path.Combine(baseUploadPath, safeFolderName, safeFileName);

        using (var fileStream = new FileStream(destinationPath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, FileOptions.None))
        {
            string error;
            if (!FileUploadValidator.IsFileValid(file.OpenReadStream(), out error))
            {
                return BadRequest(new { error });
            }
            file.CopyTo(fileStream);
        }

        return Ok(new { message = "File uploaded successfully." });
    }
    catch (Exception ex)
    {
        _logger.Error(ex, "File upload failed.");
        return StatusCode(500, new { error = "File upload failed." });
    }
}

