using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;

// Policy setup required in Startup/Program.cs:
// options.AddPolicy("WebhookAccess", policy => policy.RequireAuthenticatedUser());

namespace WebhookService.Controllers
{
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "WebhookAccess")]
    public class WebhookController : ControllerBase
    {
        private static readonly HashSet<string> AllowedHostnames = new(StringComparer.OrdinalIgnoreCase)
        {
            // Add business-approved hostnames/domains only
            "example.com",
            "api.example.com"
        };

        private static readonly HashSet<string> AllowedSchemes = new(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly IConfiguration _configuration;

        public WebhookController(IHttpClientFactory httpClientFactory, ILogger<WebhookController> logger, IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost]
        [Authorize(Policy = "WebhookAccess")]
        public async Task<IActionResult> PostAsync([FromBody] WebhookRequestDto requestDto)
        {
            try
            {
                if (requestDto == null || string.IsNullOrWhiteSpace(requestDto.CallbackUrl))
                {
                    return BadRequest(new { error = "Missing or invalid callback URL." });
                }

                if (!Uri.TryCreate(requestDto.CallbackUrl, UriKind.Absolute, out var callbackUri))
                {
                    return BadRequest(new { error = "Invalid callback URL format." });
                }

                if (!AllowedSchemes.Contains(callbackUri.Scheme))
                {
                    return BadRequest(new { error = "Only HTTPS callback URLs are allowed." });
                }

                var hostname = callbackUri.Host;
                if (!AllowedHostnames.Contains(hostname))
                {
                    return BadRequest(new { error = "The specified host is not allowed." });
                }

                if (!IsPublicAddress(hostname))
                {
                    return BadRequest(new { error = "Target host resolves to a non-public address." });
                }

                var client = _httpClientFactory.CreateClient("WebhookSafeClient");
                client.Timeout = TimeSpan.FromSeconds(10);

                var request = new HttpRequestMessage(HttpMethod.Get, callbackUri);
                var response = await client.SendAsync(request, HttpCompletionOption.ResponseHeadersRead, HttpContext.RequestAborted);

                if (response.IsSuccessStatusCode)
                {
                    _logger.LogInformation("Webhook callback {CallbackUrl} responded with {StatusCode}", requestDto.CallbackUrl, response.StatusCode);
                    return StatusCode((int)response.StatusCode);
                }
                else
                {
                    _logger.LogWarning("Webhook callback {CallbackUrl} failed with {StatusCode}", requestDto.CallbackUrl, response.StatusCode);
                    return StatusCode((int)response.StatusCode);
                }
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error processing webhook request.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private static bool IsPublicAddress(string hostname)
        {
            try
            {
                var addresses = Dns.GetHostAddresses(hostname);
                foreach (var ip in addresses)
                {
                    if (ip.AddressFamily == AddressFamily.InterNetwork || ip.AddressFamily == AddressFamily.InterNetworkV6)
                    {
                        if (IsPrivateOrReserved(ip))
                        {
                            return false;
                        }
                    }
                    else
                    {
                        return false;
                    }
                }
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool IsPrivateOrReserved(IPAddress ip)
        {
            if (IPAddress.IsLoopback(ip))
            {
                return true;
            }

            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10) return true;
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31) return true;
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168) return true;
                // APIPA 169.254.0.0/16
                if (bytes[0] == 169 && bytes[1] == 254) return true;
                // Multicast 224.0.0.0/4
                if (bytes[0] >= 224 && bytes[0] <= 239) return true;
                // 0.0.0.0/8 and 127.0.0.0/8
                if (bytes[0] == 0 || bytes[0] == 127) return true;
            }
            else if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo || ip.IsIPv6UniqueLocal)
                {
                    return true;
                }
                // ::1
                if (ip.Equals(IPAddress.IPv6Loopback)) return true;
                // ::/128 unspecified
                if (ip.Equals(IPAddress.IPv6None)) return true;
            }
            return false;
        }
    }
}

