using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace WebhookApi.Controllers
{
    // To set up the policy, add in Program.cs or Startup.cs:
    // options.AddPolicy("WebhookAccessPolicy", policy => policy.RequireAuthenticatedUser());

    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "WebhookAccessPolicy")]
    public class WebhookController : ControllerBase
    {
        private static readonly HashSet<string> AllowedHosts = new(StringComparer.OrdinalIgnoreCase)
        {
            "hooks.example.com",
            "api.external.com"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly IConfiguration _configuration;

        public WebhookController(IHttpClientFactory httpClientFactory, ILogger<WebhookController> logger, IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("test")]
        [Authorize(Policy = "WebhookAccessPolicy")]
        public async Task<IActionResult> TestWebhook([FromBody] WebhookRequestDto requestDto)
        {
            _logger.LogInformation("TestWebhook called with destination: {Destination}", requestDto.Destination);

            if (!WebhookUrlValidator.IsValidWebhookUrl(requestDto.Destination, AllowedHosts))
            {
                _logger.LogWarning("Rejected webhook request due to invalid destination.");
                return BadRequest(new { error = "Invalid webhook destination." });
            }

            var client = _httpClientFactory.CreateClient();
            client.Timeout = TimeSpan.FromSeconds(_configuration.GetValue<int?>("Webhook:TimeoutSeconds") ?? 10);
            client.DefaultRequestHeaders.Clear();

            using var httpRequest = new HttpRequestMessage(HttpMethod.Get, requestDto.Destination);
            httpRequest.Headers.Add("Accept", "application/json");

            try
            {
                using var response = await client.SendAsync(httpRequest, HttpCompletionOption.ResponseHeadersRead, HttpContext.RequestAborted);
                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Webhook request to {Destination} failed with status {StatusCode}", requestDto.Destination, response.StatusCode);
                    return StatusCode((int)response.StatusCode, new { error = "Failed to call webhook." });
                }
                var responseBody = await response.Content.ReadAsStringAsync();
                _logger.LogInformation("Webhook request to {Destination} returned {Length} bytes", requestDto.Destination, responseBody.Length);
                return Ok(responseBody);
            }
            catch (TaskCanceledException)
            {
                _logger.LogWarning("Webhook request to {Destination} timed out", requestDto.Destination);
                return BadRequest(new { error = "Webhook request timed out." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error sending webhook request to {Destination}", requestDto.Destination);
                return StatusCode(500, new { error = "Internal server error." });
            }
        }
    }
}

