// Services/WebhookUrlValidator.cs
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Sockets;

namespace WebhookApi.Services
{
    public static class WebhookUrlValidator
    {
        public static bool IsValidWebhookUrl(string urlString, HashSet<string> allowedHosts)
        {
            if (string.IsNullOrWhiteSpace(urlString))
            {
                return false;
            }

            if (!Uri.TryCreate(urlString, UriKind.Absolute, out var uri))
            {
                return false;
            }

            if (!string.Equals(uri.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            if (string.IsNullOrWhiteSpace(uri.Host) || !allowedHosts.Contains(uri.Host))
            {
                return false;
            }

            if (!IsPublicAddress(uri.Host))
            {
                return false;
            }

            return true;
        }

        private static bool IsPublicAddress(string host)
        {
            try
            {
                var addresses = Dns.GetHostAddresses(host);
                foreach (var ip in addresses)
                {
                    if (ip.AddressFamily == AddressFamily.InterNetwork || ip.AddressFamily == AddressFamily.InterNetworkV6)
                    {
                        if (IsIpPrivateOrLocal(ip))
                        {
                            return false;
                        }
                    }
                    else
                    {
                        return false;
                    }
                }
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool IsIpPrivateOrLocal(IPAddress ip)
        {
            if (IPAddress.IsLoopback(ip))
            {
                return true;
            }

            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 127.0.0.0/8
                if (bytes[0] == 127)
                {
                    return true;
                }
                // Link-local 169.254.0.0/16
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
            }
            else if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                // ::1/128 loopback
                if (ip.IsIPv6Loopback)
                {
                    return true;
                }
                // fe80::/10 link-local
                if (ip.IsIPv6LinkLocal)
                {
                    return true;
                }
                // fc00::/7 unique local
                var bytes = ip.GetAddressBytes();
                if ((bytes[0] & 0xfe) == 0xfc)
                {
                    return true;
                }
                // ::/128 unspecified
                if (ip.Equals(IPAddress.IPv6None))
                {
                    return true;
                }
            }
            return false;
        }
    }
}

