using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Configuration;
using System;
using System.Buffers.Text;
using System.Collections.Generic;
using System.Globalization;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Text.RegularExpressions;
using System.Threading;
using System.Threading.Tasks;

// Policy setup (in Program.cs or Startup.cs):
// options.AddPolicy("WebhookSubscriptionPolicy", policy => policy.RequireAuthenticatedUser());

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "WebhookSubscriptionPolicy")]
    public class WebhookController : ControllerBase
    {
        private static readonly HashSet<string> AllowedDomains = new(StringComparer.OrdinalIgnoreCase)
        {
            "example.com",
            "api.example.com"
        };

        private static readonly HashSet<string> AllowedSchemes = new(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly IConfiguration _configuration;

        public WebhookController(IHttpClientFactory httpClientFactory, ILogger<WebhookController> logger, IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost]
        [Authorize(Policy = "WebhookSubscriptionPolicy")]
        public async Task<IActionResult> PostAsync([FromBody] WebhookRequestDto requestDto, CancellationToken cancellationToken)
        {
            _logger.LogInformation("Received webhook request.");

            if (!ModelState.IsValid)
            {
                return BadRequest(new { error = "Invalid request.", details = ModelState.Values.SelectMany(v => v.Errors).Select(e => e.ErrorMessage) });
            }

            Uri targetUri;
            try
            {
                targetUri = CanonicalizeAndValidateUrl(requestDto.CallbackUrl);
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Failed to validate or canonicalize callback URL.");
                return BadRequest(new { error = "Invalid callback URL." });
            }

            // Only allow HTTPS
            if (!AllowedSchemes.Contains(targetUri.Scheme))
            {
                _logger.LogWarning("Rejected callback URL with disallowed scheme: {Scheme}", targetUri.Scheme);
                return BadRequest(new { error = "Only HTTPS callback URLs are allowed." });
            }

            // Check host allowlist
            var host = targetUri.Host;
            if (!AllowedDomains.Contains(host))
            {
                _logger.LogWarning("Rejected callback URL with disallowed host: {Host}", host);
                return BadRequest(new { error = "Callback URL host is not allowed." });
            }

            // Check DNS/IP resolution and block private/internal IPs
            try
            {
                var addresses = await Dns.GetHostAddressesAsync(host);
                foreach (var address in addresses)
                {
                    if (IsDnsResolutionUnsafe(address))
                    {
                        _logger.LogWarning("Rejected callback URL with unsafe IP address: {Address}", address);
                        return BadRequest(new { error = "Callback URL resolves to an unsafe IP address." });
                    }
                }
            }
            catch (SocketException ex)
            {
                _logger.LogWarning(ex, "DNS resolution failed for host: {Host}", host);
                return BadRequest(new { error = "Failed to resolve host." });
            }

            // Only allow POST for security
            var httpClient = _httpClientFactory.CreateClient();
            httpClient.Timeout = TimeSpan.FromSeconds(10);

            using var request = new HttpRequestMessage(HttpMethod.Post, targetUri);
            request.Content = new StringContent(string.Empty);

            try
            {
                var response = await httpClient.SendAsync(request, HttpCompletionOption.ResponseHeadersRead, cancellationToken);
                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Webhook callback to {CallbackUrl} failed with status {StatusCode}", requestDto.CallbackUrl, response.StatusCode);
                    return BadRequest(new { error = "Failed to call callback URL." });
                }
                return Ok();
            }
            catch (HttpRequestException ex)
            {
                _logger.LogError(ex, "Exception while sending webhook request.");
                return StatusCode(500, new { error = "Failed to send webhook request." });
            }
        }

        private static Uri CanonicalizeAndValidateUrl(string url)
        {
            if (string.IsNullOrWhiteSpace(url))
            {
                throw new ArgumentException("URL is required.");
            }

            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri))
            {
                throw new ArgumentException("URL is not a valid absolute URI.");
            }

            // No fragments, querystring, etc. (no need to canonicalize)
            if (!AllowedSchemes.Contains(uri.Scheme))
            {
                throw new ArgumentException("Only HTTPS scheme is allowed.");
            }

            // No credentials in url
            if (uri.UserInfo.Length > 0)
            {
                throw new ArgumentException("User info in URL is not allowed.");
            }

            return uri;
        }

        private static bool IsDnsResolutionUnsafe(IPAddress address)
        {
            if (address.AddressFamily == AddressFamily.InterNetwork || address.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (IPAddress.IsLoopback(address) ||
                    address.IsIPv6LinkLocal || address.IsIPv6SiteLocal ||
                    address.IsIPv6Multicast || address.IsIPv6Teredo ||
                    address.IsIPv6UniqueLocal)
                {
                    return true;
                }

                // RFC 1918 private IPv4
                if (address.AddressFamily == AddressFamily.InterNetwork)
                {
                    var bytes = address.GetAddressBytes();
                    if (bytes[0] == 10 ||
                        (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31) ||
                        (bytes[0] == 192 && bytes[1] == 168))
                    {
                        return true;
                    }
                }
            }
            else
            {
                return true;
            }
            return false;
        }
    }
}

