// Services/UrlPreviewService.cs
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;
using System.Text.RegularExpressions;

namespace UrlPreview.Services
{
    public class UrlPreviewService : IUrlPreviewService
    {
        private static readonly HashSet<string> AllowedDomains = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            // Add allowed domains here, e.g. "example.com", "www.example.org"
        };

        private static readonly HashSet<string> AllowedSchemes = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<UrlPreviewService> _logger;
        private readonly int _maxContentLength;

        public UrlPreviewService(IHttpClientFactory httpClientFactory, ILogger<UrlPreviewService> logger, IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _maxContentLength = configuration.GetValue<int>("UrlPreview:MaxContentLength", 10 * 1024); // 10KB default
        }

        public async Task<string> FetchUrlPreviewAsync(string url)
        {
            var validatedUri = ValidateAndCanonicalizeUrl(url);

            if (!IsAllowedDomain(validatedUri))
            {
                throw new UrlPreviewValidationException("Target domain is not allowed.");
            }

            if (!AllowedSchemes.Contains(validatedUri.Scheme))
            {
                throw new UrlPreviewValidationException("Scheme is not allowed.");
            }

            await ValidatePublicAddressAsync(validatedUri);

            var httpClient = _httpClientFactory.CreateClient("UrlPreview");
            httpClient.Timeout = TimeSpan.FromSeconds(5);
            httpClient.DefaultRequestHeaders.Clear();
            httpClient.MaxResponseContentBufferSize = _maxContentLength;

            using var request = new HttpRequestMessage(HttpMethod.Get, validatedUri);
            using var response = await httpClient.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);

            if (!response.IsSuccessStatusCode)
            {
                throw new UrlPreviewValidationException("Unable to retrieve content from the url.");
            }

            var contentType = response.Content.Headers.ContentType?.MediaType;
            if (contentType == null || !contentType.StartsWith("text/", StringComparison.OrdinalIgnoreCase))
            {
                throw new UrlPreviewValidationException("Content-Type is not allowed.");
            }

            var previewContent = await response.Content.ReadAsStringAsync();
            if (previewContent.Length > _maxContentLength)
            {
                throw new UrlPreviewValidationException("Content is too large.");
            }

            return previewContent;
        }

        private static Uri ValidateAndCanonicalizeUrl(string url)
        {
            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri))
            {
                throw new UrlPreviewValidationException("Invalid URL format.");
            }

            if (!string.IsNullOrEmpty(uri.UserInfo))
            {
                throw new UrlPreviewValidationException("User info in URL is not allowed.");
            }

            if (!AllowedSchemes.Contains(uri.Scheme))
            {
                throw new UrlPreviewValidationException("Scheme is not allowed.");
            }

            if (uri.Port == 80 || uri.Port == 443 || uri.Port == -1)
            {
                // Port is OK
            }
            else
            {
                throw new UrlPreviewValidationException("Port is not allowed.");
            }

            if (!IsPublicHost(uri.Host))
            {
                throw new UrlPreviewValidationException("Host is not allowed.");
            }

            return uri;
        }

        private static bool IsAllowedDomain(Uri uri)
        {
            // Allowlist: only allow exact match or subdomains of allowed domains
            if (AllowedDomains.Count == 0)
            {
                return false;
            }

            var host = uri.Host;
            foreach (var allowed in AllowedDomains)
            {
                if (host.Equals(allowed, StringComparison.OrdinalIgnoreCase) ||
                    (host.EndsWith("." + allowed, StringComparison.OrdinalIgnoreCase)))
                {
                    return true;
                }
            }
            return false;
        }

        private static bool IsPublicHost(string host)
        {
            if (IPAddress.TryParse(host, out var ip))
            {
                return IsPublicIp(ip);
            }

            try
            {
                var addresses = Dns.GetHostAddresses(host);
                foreach (var addr in addresses)
                {
                    if (!IsPublicIp(addr))
                    {
                        return false;
                    }
                }
                return addresses.Length > 0;
            }
            catch
            {
                return false;
            }
        }

        private static bool IsPublicIp(IPAddress ip)
        {
            if (ip.AddressFamily != AddressFamily.InterNetwork && ip.AddressFamily != AddressFamily.InterNetworkV6)
            {
                return false;
            }

            if (IPAddress.IsLoopback(ip))
            {
                return false;
            }

            var bytes = ip.GetAddressBytes();
            // IPv4 private ranges
            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                var b0 = bytes[0];
                var b1 = bytes[1];
                if (b0 >= 10 || (b0 == 0 && b1 >= 0 && b1 <= 1))
                {
                    return false;
                }
                if (b0 == 172 && b1 >= 16 && b1 <= 31)
                {
                    return false;
                }
                if (b0 == 192 && b1 == 168)
                {
                    return false;
                }
                if (b0 == 169 && b1 == 254)
                {
                    return false;
                }
                if (b0 >= 224)
                {
                    return false;
                }
            }
            // IPv6 private, link-local, multicast, loopback, unspecified
            if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo)
                {
                    return false;
                }
                if (ip.Equals(IPAddress.IPv6Loopback) || ip.Equals(IPAddress.IPv6None))
                {
                    return false;
                }
            }
            return true;
        }

        private static async Task ValidatePublicAddressAsync(Uri uri)
        {
            var host = uri.Host;
            IPAddress[] addresses;
            try
            {
                addresses = Dns.GetHostAddresses(host);
            }
            catch
            {
                throw new UrlPreviewValidationException("Unable to resolve host.");
            }
            foreach (var addr in addresses)
            {
                if (!IsPublicIp(addr))
                {
                    throw new UrlPreviewValidationException("Host resolves to a non-public IP address.");
                }
            }
        }
    }

    public class UrlPreviewValidationException : Exception
    {
        public UrlPreviewValidationException(string message) : base(message) { }
    }
}

