// Policy setup: Add policy in Program.cs or Startup.cs, e.g., options.AddPolicy("FileUploadPolicy", policy => policy.RequireAuthenticatedUser());

public class FileUploadController : Controller
{
    private readonly IFileStorageService _fileStorageService;
    private readonly IVectorExtractor _vectorExtractor;
    private readonly IPdfExtractor _pdfExtractor;
    private readonly ILogger<FileUploadController> _logger;
    private readonly IConfiguration _configuration;

    public FileUploadController(
        IFileStorageService fileStorageService,
        IVectorExtractor vectorExtractor,
        IPdfExtractor pdfExtractor,
        ILogger<FileUploadController> logger,
        IConfiguration configuration)
    {
        _fileStorageService = fileStorageService;
        _vectorExtractor = vectorExtractor;
        _pdfExtractor = pdfExtractor;
        _logger = logger;
        _configuration = configuration;
    }

    [Authorize(Policy = "FileUploadPolicy")]
    [HttpPost]
    public async Task<IActionResult> UploadFileAsync([FromForm] FileUploadRequestDto request)
    {
        if (!ModelState.IsValid)
        {
            return BadRequest(new { error = "Invalid file upload request." });
        }

        try
        {
            var allowedFileTypes = _configuration.GetSection("FileUpload:AllowedMimeTypes").Get<string[]>() ?? new[] { "image/svg+xml", "application/pdf" };
            var maxFileSize = _configuration.GetValue<long>("FileUpload:MaxFileSizeBytes", 5 * 1024 * 1024); // Default 5MB

            var fileResult = await _fileStorageService.SaveUploadedFileAsync(request.File);
            if (fileResult.IsError)
            {
                _logger.LogWarning("File upload failed: {Reason}", fileResult.ErrorReason);
                return BadRequest(new { error = fileResult.ErrorReason });
            }

            FileSignatureResult fileSignatureResult;
            using (var fileStream = fileResult.SavedFileStream)
            {
                fileSignatureResult = FileSignatureVerifier.VerifyFileSignature(fileStream, request.File.FileName);
            }

            if (!fileSignatureResult.IsValid)
            {
                _logger.LogWarning("File signature invalid: {Reason}", fileSignatureResult.ErrorReason);
                return BadRequest(new { error = fileSignatureResult.ErrorReason });
            }

            string vectorContent = await ExtractVectorContentAsync(fileResult.SavedFilePath);
            string pageCount = await ExtractPageCountAsync(fileResult.SavedFilePath);

            // Compose response safe content and delete file
            await FileSecurityHelper.DeleteFileSafeAsync(fileResult.SavedFilePath);

            // Example response: do not expose path or file content directly.
            return Ok(new
            {
                message = "File uploaded and processed successfully.",
                fileType = fileSignatureResult.FileType,
                vectorContent = vectorContent,
                pageCount = pageCount
            });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error during file upload.");
            return StatusCode(500, new { error = "An error occurred while processing your file." });
        }
    }

    private async Task<string> ExtractVectorContentAsync(string filePath)
    {
        using (var fileStream = File.OpenRead(filePath))
        {
            return await _vectorExtractor.ExtractVectorDataAsync(fileStream);
        }
    }

    private async Task<string> ExtractPageCountAsync(string filePath)
    {
        using (var fileStream = File.OpenRead(filePath))
        {
            return await _pdfExtractor.ExtractPageCountAsync(fileStream);
        }
    }
}

// FileSignatureVerifier.cs

using System;
using System.Collections.Generic;
using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;

public static class FileSignatureVerifier
{
    private static readonly IReadOnlyDictionary<string, byte[]> _svgMagicNumbers = new Dictionary<string, byte[]>
    {
        { "image/svg+xml", new byte[] { 0x3C, 0x73, 0x76, 0x67 } } // "<svg"
    };

    private static readonly IReadOnlyDictionary<string, byte[]> _pdfMagicNumbers = new Dictionary<string, byte[]>
    {
        { "application/pdf", new byte[] { 0x25, 0x50, 0x44, 0x46 } } // "%PDF"
    };

    public static FileSignatureResult VerifyFileSignature(Stream fileStream, string fileName)
    {
        try
        {
            fileStream.Position = 0;
            long fileLength = fileStream.Length;
            byte[] buffer = new byte[16];
            int bytesRead = fileStream.Read(buffer, 0, buffer.Length);
            fileStream.Position = 0;

            string fileNameLower = fileName?.ToLowerInvariant() ?? "";

            if (_svgMagicNumbers.TryGetValue(fileNameLower.EndsWith(".svg") ? "image/svg+xml" : "application/octet-stream", out var svgMagic))
            {
                if (bytesRead < svgMagic.Length)
                {
                    return FileSignatureResult.Invalid("File is too short to contain SVG signature.");
                }
                if (!IsMatch(buffer, svgMagic))
                {
                    return FileSignatureResult.Invalid("File signature does not match SVG format.");
                }
                return FileSignatureResult.Valid("image/svg+xml");
            }

            if (_pdfMagicNumbers.TryGetValue(fileNameLower.EndsWith(".pdf") ? "application/pdf" : "application/octet-stream", out var pdfMagic))
            {
                if (bytesRead < pdfMagic.Length)
                {
                    return FileSignatureResult.Invalid("File is too short to contain PDF signature.");
                }
                if (!IsMatch(buffer, pdfMagic))
                {
                    return FileSignatureResult.Invalid("File signature does not match PDF format.");
                }
                return FileSignatureResult.Valid("application/pdf");
            }

            return FileSignatureResult.Invalid("File type not allowed.");
        }
        catch
        {
            return FileSignatureResult.Invalid("Error verifying file signature.");
        }
    }

    private static bool IsMatch(byte[] fileBytes, byte[] magic)
    {
        if (fileBytes.Length < magic.Length)
        {
            return false;
        }
        for (int i = 0; i < magic.Length; i++)
        {
            if (fileBytes[i] != magic[i])
            {
                return false;
            }
        }
        return true;
    }
}

