// FileStorageService.cs

using System;
using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;

public class FileStorageService : IFileStorageService
{
    private readonly string _uploadDirectory;
    private static readonly string[] AllowedExtensions = new[] { ".svg", ".pdf" };

    public FileStorageService(IConfiguration configuration)
    {
        _uploadDirectory = configuration.GetValue<string>("FileUpload:UploadDirectory") ?? Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "uploads");
        if (!Directory.Exists(_uploadDirectory))
        {
            Directory.CreateDirectory(_uploadDirectory);
        }
    }

    public async Task<FileResult> SaveUploadedFileAsync(IFormFile file)
    {
        try
        {
            if (file == null || file.Length == 0)
            {
                return FileResult.Error("No file uploaded.");
            }

            if (file.Length > (5 * 1024 * 1024))
            {
                return FileResult.Error("File size exceeds the allowed limit.");
            }

            string originalFileName = Path.GetFileName(file.FileName);
            if (string.IsNullOrWhiteSpace(originalFileName) || originalFileName.Length > 128)
            {
                return FileResult.Error("Invalid file name.");
            }

            string fileExtension = Path.GetExtension(originalFileName).ToLowerInvariant();
            if (Array.IndexOf(FileUploadRequestDto.AllowedExtensions, fileExtension) < 0)
            {
                return FileResult.Error("File type not allowed.");
            }

            string safeFileName = $"{Guid.NewGuid()}{fileExtension}";
            string filePath = Path.Combine(_uploadDirectory, safeFileName);

            if (!IsSafePath(filePath))
            {
                return FileResult.Error("Invalid file path.");
            }

            using (var stream = new FileStream(filePath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, true))
            {
                await file.CopyToAsync(stream);
            }

            // Set least-privilege permissions (for user running the app)
            SetFilePermissionsSafe(filePath);

            return FileResult.Success(new FileStream(filePath, FileMode.Open, FileAccess.Read, FileShare.Read));
        }
        catch (Exception ex)
        {
            // Do not leak details to end-user
            return FileResult.Error("File upload failed.");
        }
    }

    private static bool IsSafePath(string filePath)
    {
        var fullPath = Path.GetFullPath(filePath);
        var fullUploadDir = Path.GetFullPath(_uploadDirectory);
        return fullPath.StartsWith(fullUploadDir, StringComparison.OrdinalIgnoreCase);
    }

    private static void SetFilePermissionsSafe(string filePath)
    {
        // On Windows, files inherit directory permissions. On Linux, optionally set 0600.
        try
        {
            if (OperatingSystem.IsLinux())
            {
                Mono.Unix.Native.Syscall.chmod(filePath, Mono.Unix.Native.FilePermissions.S_IRUSR | Mono.Unix.Native.FilePermissions.S_IWUSR);
            }
        }
        catch { /* Ignore errors on non-Linux platforms or missing Mono.Unix */ }
    }
}

