using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using System.Net;
using System.Net.Http;
using System.Threading.Tasks;
using System;
using System.Linq;
using System.Text.RegularExpressions;
using System.Collections.Generic;

// Set up the policy in Program.cs or Startup.cs:
// services.AddAuthorization(options => { options.AddPolicy("CanPreviewLink", policy => policy.RequireAuthenticatedUser()); });

namespace YourApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "CanPreviewLink")]
    public class LinkController : ControllerBase
    {
        private static readonly HashSet<string> AllowedDomains = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "example.com",
            "www.example.com"
            // Add more allowed domains as required by business logic
        };

        private static readonly HashSet<string> AllowedSchemes = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<LinkController> _logger;

        public LinkController(IHttpClientFactory httpClientFactory, ILogger<LinkController> logger)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
        }

        [HttpPost("preview")]
        [Authorize(Policy = "CanPreviewLink")]
        public async Task<IActionResult> PreviewLinkAsync([FromBody] LinkPreviewRequestDto request)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(new { error = "Invalid input." });
            }

            string title;
            try
            {
                var uri = CanonicalizeAndValidateUrl(request.Url);
                var client = _httpClientFactory.CreateClient("LinkPreview");
                client.Timeout = TimeSpan.FromSeconds(5);

                var httpRequest = new HttpRequestMessage(HttpMethod.Get, uri);
                httpRequest.Headers.UserAgent.ParseAdd("Mozilla/5.0 (compatible; LinkPreviewBot/1.0)");

                var httpResponse = await client.SendAsync(httpRequest, HttpCompletionOption.ResponseHeadersRead, HttpContext.RequestAborted);

                if (!httpResponse.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Failed to preview link {Link}. Status: {StatusCode}", request.Url, httpResponse.StatusCode);
                    return NotFound(new { error = "Unable to preview link." });
                }

                var contentType = httpResponse.Content.Headers.ContentType?.MediaType;
                if (contentType == null || !contentType.StartsWith("text/html", StringComparison.OrdinalIgnoreCase))
                {
                    _logger.LogWarning("Link preview rejected non-HTML content {ContentType}", contentType);
                    return NotFound(new { error = "Unable to preview link (not HTML)." });
                }

                var html = await httpResponse.Content.ReadAsStringAsync(HttpContext.RequestAborted);
                title = ExtractTitleFromHtml(html);
            }
            catch (UriFormatException)
            {
                return BadRequest(new { error = "Invalid URL format." });
            }
            catch (HttpRequestException ex)
            {
                _logger.LogWarning(ex, "HttpRequestException for link preview");
                return StatusCode(500, new { error = "Failed to preview link." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error in LinkPreview");
                return StatusCode(500, new { error = "Internal server error." });
            }

            if (string.IsNullOrWhiteSpace(title))
            {
                return NotFound(new { error = "Unable to extract title." });
            }

            return Ok(new { title });
        }

        private static Uri CanonicalizeAndValidateUrl(string url)
        {
            if (string.IsNullOrWhiteSpace(url))
            {
                throw new UriFormatException("URL is empty.");
            }

            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri))
            {
                throw new UriFormatException("Invalid URL format.");
            }

            if (!AllowedSchemes.Contains(uri.Scheme))
            {
                throw new UriFormatException("Scheme not allowed.");
            }

            var host = uri.Host.TrimEnd('.').ToLowerInvariant();

            // Allowlist domain check
            if (!AllowedDomains.Any(domain =>
                host == domain ||
                (host == "www." + domain)))
            {
                throw new UriFormatException("Domain is not allowed.");
            }

            // Resolve DNS to check for local/private addresses
            var addresses = Dns.GetHostAddresses(host);
            foreach (var ip in addresses)
            {
                if (IsIpAddressUnsafe(ip))
                {
                    throw new UriFormatException("Domain resolves to an unsafe address.");
                }
            }

            return uri;
        }

        private static bool IsIpAddressUnsafe(IPAddress ip)
        {
            if (ip.AddressFamily == System.Net.Sockets.AddressFamily.InterNetworkV6)
            {
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo)
                {
                    return true;
                }
            }

            if (IPAddress.IsLoopback(ip) ||
                ip.Equals(IPAddress.Any) ||
                ip.Equals(IPAddress.IPv6Any) ||
                ip.Equals(IPAddress.Broadcast) ||
                ip.Equals(IPAddress.None) ||
                ip.Equals(IPAddress.IPv6None) ||
                ip.Equals(IPAddress.IPv6Loopback))
            {
                return true;
            }

            // Check private IPv4 ranges
            byte[] bytes = ip.GetAddressBytes();
            switch (bytes[0])
            {
                case 10:
                case 127:
                    return true;
                case 172:
                    if (bytes[1] >= 16 && bytes[1] <= 31)
                        return true;
                    break;
                case 192:
                    if (bytes[1] == 168)
                        return true;
                    break;
            }
            return false;
        }

        private static string ExtractTitleFromHtml(string html)
        {
            if (string.IsNullOrWhiteSpace(html))
            {
                return null;
            }

            // Simple HTML title extraction
            var match = Regex.Match(html, @"<title[^>]*>(.*?)</title>", RegexOptions.IgnoreCase | RegexOptions.Singleline);
            if (match.Success && match.Groups.Count > 1)
            {
                return match.Groups[1].Value.Trim();
            }
            return null;
        }
    }
}

