using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using System;
using System.Collections.Generic;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading;
using System.Threading.Tasks;

namespace YourNamespace.Controllers
{
    // Set up the policy in Program.cs or Startup.cs:
    // services.AddAuthorization(options => { options.AddPolicy("CanPreviewLink", policy => policy.RequireAuthenticatedUser()); });

    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "CanPreviewLink")]
    public class LinkController : ControllerBase
    {
        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<LinkController> _logger;
        private readonly HashSet<string> _allowedDomains;
        private readonly int _httpTimeoutSeconds;

        public LinkController(
            IHttpClientFactory httpClientFactory,
            ILogger<LinkController> logger,
            IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _allowedDomains = new HashSet<string>(
                configuration.GetSection("LinkPreview:AllowedDomains").Get<string[]>() ?? Array.Empty<string>(),
                StringComparer.OrdinalIgnoreCase
            );
            _httpTimeoutSeconds = configuration.GetValue<int>("LinkPreview:TimeoutSeconds", 5);
        }

        [HttpPost("title")]
        [Authorize(Policy = "CanPreviewLink")]
        public async Task<IActionResult> GetTitleAsync([FromBody] LinkPreviewRequestDto request, CancellationToken cancellationToken)
        {
            try
            {
                if (!LinkPreviewRequestDto.TryValidate(request, _allowedDomains, _logger, out var validationError))
                {
                    return BadRequest(new { error = validationError });
                }

                var uri = new Uri(request.Url, UriKind.Absolute);

                if (!IsSchemeAllowed(uri))
                {
                    _logger.LogWarning("Rejected link with disallowed scheme: {Url}", request.Url);
                    return BadRequest(new { error = "Only HTTP and HTTPS schemes are allowed." });
                }

                if (!IsPublicAddress(uri, _logger))
                {
                    _logger.LogWarning("Rejected link to non-public IP: {Url}", request.Url);
                    return BadRequest(new { error = "Target host resolves to a non-public IP address." });
                }

                var httpClient = _httpClientFactory.CreateClient("LinkPreview");
                httpClient.Timeout = TimeSpan.FromSeconds(_httpTimeoutSeconds);

                var httpRequest = new HttpRequestMessage(HttpMethod.Get, uri)
                {
                    Version = new Version(1, 1)
                };
                httpRequest.Headers.UserAgent.ParseAdd("LinkPreviewBot/1.0");

                var httpResponse = await httpClient.SendAsync(httpRequest, HttpCompletionOption.ResponseHeadersRead, cancellationToken);

                if (!httpResponse.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Failed to fetch URL preview: {Url}, Status: {StatusCode}", request.Url, httpResponse.StatusCode);
                    return NotFound(new { error = "Could not fetch the webpage title." });
                }

                var contentType = httpResponse.Content.Headers.ContentType?.MediaType;
                if (contentType is not null && !contentType.Contains("html", StringComparison.OrdinalIgnoreCase))
                {
                    _logger.LogWarning("Rejected link with non-HTML content type: {ContentType}, {Url}", contentType, request.Url);
                    return BadRequest(new { error = "Only HTML content is supported." });
                }

                var title = await httpResponse.Content.ReadAsStringAsync(cancellationToken);
                var titleMatch = TitleTagRegex.Match(title);

                if (titleMatch.Success)
                {
                    var titleString = titleMatch.Groups["title"].Value?.Trim();
                    return Ok(new { title = titleString });
                }

                _logger.LogWarning("Failed to extract title from link preview content. {Url}", request.Url);
                return NotFound(new { error = "Could not extract the title from the webpage." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error while previewing link.");
                return StatusCode(500, new { error = "An unexpected error occurred." });
            }
        }

        private static bool IsSchemeAllowed(Uri uri)
        {
            return uri.Scheme.Equals(Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase)
                || uri.Scheme.Equals(Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase);
        }

        private static bool IsPublicAddress(Uri uri, ILogger logger)
        {
            try
            {
                var host = uri.Host;
                var addresses = Dns.GetHostAddresses(host);

                foreach (var ip in addresses)
                {
                    if (IsPrivateOrLocalIp(ip))
                    {
                        logger.LogWarning("Rejected link with private/local IP: {Ip}", ip);
                        return false;
                    }
                }
                return true;
            }
            catch (Exception ex)
            {
                logger.LogWarning(ex, "Failed to resolve host: {Host}", uri.Host);
                return false;
            }
        }

        private static bool IsPrivateOrLocalIp(IPAddress ip)
        {
            if (IPAddress.IsLoopback(ip))
            {
                return true;
            }

            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
            }
            else if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo)
                {
                    return true;
                }
                if (ip.Equals(IPAddress.IPv6Loopback))
                {
                    return true;
                }
            }
            return false;
        }

        private static readonly System.Text.RegularExpressions.Regex TitleTagRegex = new(
            @"<title(?:[^>]*)>(?<title>[^\s]*)(?:[^>]*)</title>",
            System.Text.RegularExpressions.RegexOptions.IgnoreCase | System.Text.RegularExpressions.RegexOptions.Compiled
        );
    }

