using System;
using System.Collections.Generic;
using System.Text.RegularExpressions;
using Microsoft.Extensions.Logging;

namespace YourNamespace.Dtos
{
    public class LinkPreviewRequestDto
    {
        public string Url { get; set; }

        private static readonly Regex UrlRegex = new(@"^https?://[^ ]+", RegexOptions.Compiled | RegexOptions.IgnoreCase);

        private readonly HashSet<string> _allowedDomains;
        private readonly ILogger _logger;

        public LinkPreviewRequestDto(HashSet<string> allowedDomains, ILogger logger)
        {
            _allowedDomains = allowedDomains;
            _logger = logger;
        }

        public static bool TryValidate(LinkPreviewRequestDto dto, HashSet<string> allowedDomains, ILogger logger, out string error)
        {
            error = null;
            if (dto == null)
            {
                error = "Missing request data.";
                return false;
            }
            if (string.IsNullOrWhiteSpace(dto.Url))
            {
                error = "Url is required.";
                return false;
            }
            if (!UrlRegex.IsMatch(dto.Url))
            {
                error = "Url is not a valid format.";
                return false;
            }
            if (allowedDomains.Count > 0)
            {
                var host = new Uri(dto.Url, UriKind.Absolute).Host;
                if (!string.IsNullOrEmpty(host) && !allowedDomains.Contains(host))
                {
                    logger.LogWarning("Host {Host} is not in the allowlist.", host);
                    error = "Host is not allowed.";
                    return false;
                }
            }
            return true;
        }
    }
}

