using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

// Policy setup required in Program.cs or Startup.cs:
// options.AddPolicy("WebhookAccess", policy => policy.RequireAuthenticatedUser());

namespace MyApp.Controllers
{
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "WebhookAccess")]
    public class WebhookController : ControllerBase
    {
        private static readonly HashSet<string> AllowedHostnames = new(StringComparer.OrdinalIgnoreCase)
        {
            "api.example.com",
            "webhook.partner.com"
        };

        private static readonly HashSet<string> AllowedSchemes = new(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly IConfiguration _configuration;

        public WebhookController(IHttpClientFactory httpClientFactory, ILogger<WebhookController> logger, IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost]
        [Route("fetch")]
        [Authorize(Policy = "WebhookAccess")]
        public async Task<IActionResult> FetchData([FromBody] WebhookRequestDto requestDto)
        {
            _logger.LogInformation("Webhook fetch requested for target: {Target}", requestDto?.TargetUrl);

            if (requestDto == null || string.IsNullOrWhiteSpace(requestDto.TargetUrl))
            {
                return BadRequest(new { error = "Target URL is required." });
            }

            if (!TryValidateAndCanonicalizeUrl(requestDto.TargetUrl, out var uri, out var validationError))
            {
                _logger.LogWarning("Webhook target validation failed: {Error}", validationError);
                return BadRequest(new { error = validationError });
            }

            var client = _httpClientFactory.CreateClient("WebhookSafeClient");
            client.Timeout = TimeSpan.FromSeconds(_configuration.GetValue<int>("Webhook:TimeoutSeconds", 10));

            var httpRequest = new HttpRequestMessage(HttpMethod.Get, uri);

            try
            {
                var response = await client.SendAsync(httpRequest, HttpCompletionOption.ResponseHeadersRead);
                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Webhook fetch failed with status: {Status}", response.StatusCode);
                    return StatusCode((int)response.StatusCode, new { error = "Failed to fetch data from upstream." });
                }
                var content = await response.Content.ReadAsStringAsync();
                _logger.LogInformation("Webhook fetch succeeded for target: {Target}", uri);
                return Ok(content);
            }
            catch (HttpRequestException ex)
            {
                _logger.LogError(ex, "Webhook http request exception for target: {Target}", uri);
                return StatusCode(500, new { error = "Failed to fetch data from upstream." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Webhook unexpected exception for target: {Target}", uri);
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private static bool TryValidateAndCanonicalizeUrl(string inputUrl, out Uri uri, out string error)
        {
            uri = null;
            error = null;

            if (!Uri.TryCreate(inputUrl, UriKind.Absolute, out var parsedUri))
            {
                error = "Invalid URL format.";
                return false;
            }

            if (!AllowedSchemes.Contains(parsedUri.Scheme))
            {
                error = "Only HTTPS protocol is allowed.";
                return false;
            }

            if (string.IsNullOrWhiteSpace(parsedUri.Host))
            {
                error = "URL host is required.";
                return false;
            }

            // Host must match allowlist
            if (!AllowedHostnames.Contains(parsedUri.Host))
            {
                error = "Host is not allowed.";
                return false;
            }

            // Check for IP addresses and block private/local addresses
            if (IPAddress.TryParse(parsedUri.Host, out var ip))
            {
                if (!IsPublicAddress(ip))
                {
                    error = "IP address is not allowed.";
                    return false;
                }
            }

            uri = parsedUri;
            return true;
        }

        private static bool IsPublicAddress(IPAddress ip)
        {
            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10) return false;
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31) return false;
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168) return false;
                // 127.0.0.0/8
                if (bytes[0] == 127) return false;
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254) return false;
                // 0.0.0.0/8 (unspecified)
                if (bytes[0] == 0) return false;
                // 224.0.0.0/4 (multicast)
                if (bytes[0] >= 224 && bytes[0] <= 239) return false;
            }
            else if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                // ::1/128 (loopback)
                if (ip.IsIPv6Loopback) return false;
                // fc00::/7 (unique local)
                if (ip.IsIPv6SiteLocal || ip.IsIPv6UniqueLocal) return false;
                // fe80::/10 (link-local)
                if (ip.IsIPv6LinkLocal) return false;
                // ff00::/8 (multicast)
                if (ip.IsIPv6Multicast) return false;
                // ::/128 (unspecified)
                if (ip.Equals(IPAddress.IPv6None)) return false;
            }
            return true;
        }
    }

