using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;

namespace MyApp
{
    public class Program
    {
        public static void Main(string[] args)
        {
            var builder = WebApplication.CreateBuilder(args);

            builder.Services.AddControllers();

            builder.Services.AddHttpClient("WebhookSafeClient", client =>
            {
                client.DefaultRequestHeaders.UserAgent.ParseAdd("MyApp-Webhook/1.0");
                client.Timeout = TimeSpan.FromSeconds(builder.Configuration.GetValue<int>("Webhook:TimeoutSeconds", 10));
            })
            .ConfigurePrimaryHttpMessageHandler(() =>
            {
                var handler = new HttpClientHandler
                {
                    AllowAutoRedirect = false // Prevent automatic redirects to unvalidated endpoints
                };
                return handler;
            });

            builder.Services.AddAuthorization(options =>
            {
                options.AddPolicy("WebhookAccess", policy =>
                {
                    policy.RequireAuthenticatedUser();
                });
            });

            var app = builder.Build();

            if (app.Environment.IsDevelopment())
            {
                app.UseDeveloperExceptionPage();
            }

            app.UseHttpsRedirection();

            app.UseRouting();

            app.UseAuthorization();

            app.MapControllers();

            app.Run();
        }
    }
}

