using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using MyApp.Models;
using MyApp.Services;
using System;
using System.Collections.Generic;
using System.Net;
using System.Threading.Tasks;

namespace MyApp.Controllers
{
    // To use the policy, set up in Program.cs or Startup.cs:
    // services.AddAuthorization(options => { options.AddPolicy("ContentFetchPolicy", policy => policy.RequireAuthenticatedUser()); });
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "ContentFetchPolicy")]
    public class ContentController : ControllerBase
    {
        private readonly IContentFetcher _contentFetcher;
        private readonly ILogger<ContentController> _logger;

        public ContentController(IContentFetcher contentFetcher, ILogger<ContentController> logger)
        {
            _contentFetcher = contentFetcher;
            _logger = logger;
        }

        [HttpPost("get")]
        [Authorize(Policy = "ContentFetchPolicy")]
        public async Task<IActionResult> GetContentAsync([FromBody] ContentGetRequestDto request)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(new { error = "Invalid input." });
            }

            try
            {
                _logger.LogInformation("Fetching content for target: {Target}", request.Target);

                var content = await _contentFetcher.FetchContentAsync(request.Target);

                if (content == null)
                {
                    return NotFound();
                }

                return Ok(new { content });
            }
            catch (ContentFetcherValidationException ex)
            {
                _logger.LogWarning("Validation failed for target: {Target} Reason: {Reason}", request.Target, ex.Message);
                return BadRequest(new { error = ex.Message });
            }
            catch (ContentFetcherNotAllowedException ex)
            {
                _logger.LogWarning("Attempt to access forbidden target: {Target} Reason: {Reason}", request.Target, ex.Message);
                return BadRequest(new { error = "Forbidden target." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error fetching content for target: {Target}", request.Target);
                return StatusCode((int)HttpStatusCode.InternalServerError, new { error = "Internal error." });
            }
        }
    }
}

