// Services/ContentFetcher.cs
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;

namespace MyApp.Services
{
    public class ContentFetcher : IContentFetcher
    {
        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<ContentFetcher> _logger;
        private readonly IConfiguration _configuration;

        // For demonstration, allowlist only known domains
        private static readonly HashSet<string> AllowedDomains = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "example.com",
            "docs.example.com"
        };

        private const int MaxContentLength = 1024 * 1024; // 1MB

        public ContentFetcher(
            IHttpClientFactory httpClientFactory,
            ILogger<ContentFetcher> logger,
            IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        public async Task<string> FetchContentAsync(string target)
        {
            var uri = ValidateAndCanonicalizeTarget(target);

            if (!IsDomainAllowed(uri.Host))
            {
                throw new ContentFetcherNotAllowedException("Forbidden host.");
            }

            if (!IsPublicAddress(uri.Host))
            {
                throw new ContentFetcherNotAllowedException("Forbidden IP address.");
            }

            var client = _httpClientFactory.CreateClient("ContentFetcher");
            client.Timeout = TimeSpan.FromSeconds(5);
            client.DefaultRequestHeaders.Clear();
            client.MaxResponseContentBufferSize = MaxContentLength;

            using var request = new HttpRequestMessage(HttpMethod.Get, uri);
            using var response = await client.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);

            if (!response.IsSuccessStatusCode)
            {
                throw new ContentFetcherValidationException("Failed to fetch content.");
            }

            if (response.Content.Headers.ContentLength > MaxContentLength)
            {
                throw new ContentFetcherValidationException("Content too large.");
            }

            var contentType = response.Content.Headers.ContentType?.MediaType;
            if (contentType != null && !contentType.StartsWith("text/", StringComparison.OrdinalIgnoreCase))
            {
                throw new ContentFetcherValidationException("Only text content supported.");
            }

            var content = await response.Content.ReadAsStringAsync();
            if (string.IsNullOrWhiteSpace(content))
            {
                throw new ContentFetcherValidationException("Empty content.");
            }

            return content;
        }

        private static Uri ValidateAndCanonicalizeTarget(string target)
        {
            if (!Uri.TryCreate(target, UriKind.Absolute, out var uri))
            {
                throw new ContentFetcherValidationException("Invalid target URL.");
            }

            if (!string.Equals(uri.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase))
            {
                throw new ContentFetcherValidationException("Only HTTPS scheme is allowed.");
            }

            if (string.IsNullOrWhiteSpace(uri.Host))
            {
                throw new ContentFetcherValidationException("Target host is required.");
            }

            return uri;
        }

        private static bool IsDomainAllowed(string host)
        {
            // If you want to allow only specific domains, uncomment this and remove the "allowedDomains" comment.
            // Example: return AllowedDomains.Contains(host.Split('.').Reverse().SkipWhile(s => s != "com").Reverse().First());
            return AllowedDomains.Contains(host);
        }

        private static bool IsPublicAddress(string host)
        {
            try
            {
                var addresses = Dns.GetHostAddresses(host);
                foreach (var addr in addresses)
                {
                    if (addr.AddressFamily == AddressFamily.InterNetwork || addr.AddressFamily == AddressFamily.InterNetworkV6)
                    {
                        if (IsPrivateOrReservedIp(addr))
                        {
                            return false;
                        }
                    }
                }
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool IsPrivateOrReservedIp(IPAddress ip)
        {
            if (IPAddress.IsLoopback(ip))
            {
                return true;
            }

            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
                // 127.0.0.0/8 (loopback)
                if (bytes[0] == 127)
                {
                    return true;
                }
                // 0.0.0.0/8 (unspecified)
                if (bytes[0] == 0)
                {
                    return true;
                }
                // 224.0.0.0/4 (multicast)
                if (bytes[0] >= 224 && bytes[0] <= 239)
                {
                    return true;
                }
                // 240.0.0.0/4 (reserved)
                if (bytes[0] >= 240)
                {
                    return true;
                }
            }
            else if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo || ip.IsIPv6UniqueLocal)
                {
                    return true;
                }
                if (ip.Equals(IPAddress.IPv6Loopback) || ip.Equals(IPAddress.IPv6None) || ip.Equals(IPAddress.IPv6Any))
                {
                    return true;
                }
            }
            return false;
        }
    }
}

