using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Configuration;
using System;
using System.Collections.Generic;
using System.Net.Http;
using System.Threading.Tasks;
using System.Net;
using System.Linq;
using System.Text.RegularExpressions;

// Policy setup required in Program.cs or Startup.cs:
// services.AddAuthorization(options => { options.AddPolicy("WebhookAccessPolicy", policy => policy.RequireAuthenticatedUser()); });

namespace WebhookService.Controllers
{
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "WebhookAccessPolicy")]
    public class WebhookController : ControllerBase
    {
        private static readonly HashSet<string> AllowedHostnames = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            // Add only business-approved hostnames or domains here
            "api.example.com",
            "webhook.partner.com"
        };

        private static readonly HashSet<string> AllowedSchemes = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly IConfiguration _configuration;

        public WebhookController(IHttpClientFactory httpClientFactory, ILogger<WebhookController> logger, IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost]
        [Route("test")]
        [Authorize(Policy = "WebhookAccessPolicy")]
        public async Task<IActionResult> TestWebhookAsync([FromBody] WebhookRequestDto requestDto)
        {
            _logger.LogInformation("Received webhook test request for URL: {Url}", requestDto?.Url);

            if (requestDto == null || string.IsNullOrWhiteSpace(requestDto.Url))
            {
                return BadRequest(new { error = "Missing or invalid input." });
            }

            Uri uri;
            try
            {
                uri = new Uri(requestDto.Url, UriKind.Absolute);
            }
            catch (Exception)
            {
                return BadRequest(new { error = "Malformed URL." });
            }

            if (!AllowedSchemes.Contains(uri.Scheme))
            {
                return BadRequest(new { error = "Only HTTPS scheme is allowed." });
            }

            if (string.IsNullOrWhiteSpace(uri.Host) || !Regex.IsMatch(uri.Host, @"^[a-zA-Z0-9.-]+$"))
            {
                return BadRequest(new { error = "Invalid host." });
            }

            string canonicalHost = uri.Host.Trim().ToLowerInvariant();

            if (!AllowedHostnames.Contains(canonicalHost))
            {
                return BadRequest(new { error = "Host not allowed." });
            }

            IPAddress[] hostAddresses;
            try
            {
                hostAddresses = await Dns.GetHostAddressesAsync(canonicalHost);
            }
            catch (Exception)
            {
                return BadRequest(new { error = "Unable to resolve host." });
            }

            foreach (var addr in hostAddresses)
            {
                if (IsPrivateOrUnsafeAddress(addr))
                {
                    return BadRequest(new { error = "Access to private or unsafe addresses is not allowed." });
                }
            }

            try
            {
                var client = _httpClientFactory.CreateClient(nameof(WebhookController));
                client.Timeout = TimeSpan.FromSeconds(10);

                var request = new HttpRequestMessage(HttpMethod.Get, uri);
                request.Headers.UserAgent.ParseAdd("WebhookService/1.0");

                using var response = await client.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);

                _logger.LogInformation("Webhook test HTTP GET to {Url} returned {StatusCode}", requestDto.Url, response.StatusCode);

                return StatusCode((int)response.StatusCode);
            }
            catch (HttpRequestException ex)
            {
                _logger.LogWarning(ex, "HTTP request failed for {Url}", requestDto.Url);
                return BadRequest(new { error = "Failed to reach the URL." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error in webhook test.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private static bool IsPrivateOrUnsafeAddress(IPAddress address)
        {
            if (IPAddress.IsLoopback(address))
            {
                return true;
            }

            if (address.AddressFamily == System.Net.Sockets.AddressFamily.InterNetwork)
            {
                byte[] bytes = address.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
                // 127.0.0.0/8 (loopback)
                if (bytes[0] == 127)
                {
                    return true;
                }
            }
            else if (address.AddressFamily == System.Net.Sockets.AddressFamily.InterNetworkV6)
            {
                if (address.IsIPv6LinkLocal || address.IsIPv6Multicast || address.IsIPv6SiteLocal || address.IsIPv6Teredo)
                {
                    return true;
                }
                if (address.Equals(IPAddress.IPv6Loopback) || address.Equals(IPAddress.IPv6None))
                {
                    return true;
                }
            }
            return false;
        }
    }
}

