using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace YourNamespace.Controllers
{
    // Policy setup: In Startup/Program, configure an authorization policy named "WebhookFetchPolicy"
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "WebhookFetchPolicy")]
    public class WebhookController : ControllerBase
    {
        private static readonly HashSet<string> AllowedDomains = new(StringComparer.OrdinalIgnoreCase)
        {
            // Add your approved domains here
            "example.com",
            "api.example.com"
        };

        private static readonly HashSet<string> AllowedSchemes = new(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly IConfiguration _configuration;

        public WebhookController(
            IHttpClientFactory httpClientFactory,
            ILogger<WebhookController> logger,
            IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("fetch")]
        [Authorize(Policy = "WebhookFetchPolicy")]
        public async Task<IActionResult> FetchDataAsync([FromBody] WebhookFetchRequestDto request)
        {
            _logger.LogInformation("Webhook fetch requested for inputId {InputId}", request?.Id);

            if (request == null || string.IsNullOrWhiteSpace(request.Id))
            {
                return BadRequest(new { error = "Invalid request." });
            }

            try
            {
                // Only allow fetching from explicitly allowed domains
                if (!AllowedDomains.Contains(request.Id))
                {
                    _logger.LogWarning("Rejected request: Domain not allowed. InputId: {InputId}", request.Id);
                    return NotFound();
                }

                var url = $"https://{request.Id}/";
                if (!Uri.TryCreate(url, UriKind.Absolute, out var uri) || !AllowedSchemes.Contains(uri.Scheme))
                {
                    _logger.LogWarning("Rejected request: Invalid URL scheme or format. InputId: {InputId}", request.Id);
                    return BadRequest(new { error = "Invalid URL." });
                }

                // Resolve DNS and check IPs for SSRF
                IPAddress[] addresses;
                try
                {
                    addresses = await Dns.GetHostAddressesAsync(uri.Host);
                }
                catch (SocketException)
                {
                    _logger.LogWarning("Rejected request: DNS resolution failed. InputId: {InputId}", request.Id);
                    return NotFound();
                }

                foreach (var address in addresses)
                {
                    if (IsIpAddressForbidden(address))
                    {
                        _logger.LogWarning("Rejected request: IP not allowed. InputId: {InputId}, IP: {IP}", request.Id, address);
                        return NotFound();
                    }
                }

                var client = _httpClientFactory.CreateClient(nameof(WebhookController));
                client.Timeout = TimeSpan.FromSeconds(10);
                client.DefaultRequestHeaders.Clear();

                using var requestMessage = new HttpRequestMessage(HttpMethod.Get, uri);
                var response = await client.SendAsync(requestMessage, HttpCompletionOption.ResponseHeadersRead, HttpContext.RequestAborted);

                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Webhook fetch failed for {InputId}. Status: {StatusCode}", request.Id, response.StatusCode);
                    return StatusCode((int)HttpStatusCode.BadGateway, new { error = "Failed to fetch data." });
                }

                var contentStream = await response.Content.ReadAsStreamAsync(HttpContext.RequestAborted);
                return File(contentStream, "application/octet-stream");
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error in webhook fetch.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private static bool IsIpAddressForbidden(IPAddress address)
        {
            if (IPAddress.IsLoopback(address))
            {
                return true;
            }

            if (address.AddressFamily == AddressFamily.InterNetwork)
            {
                // IPv4
                byte[] bytes = address.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 127.0.0.0/8
                if (bytes[0] == 127)
                {
                    return true;
                }
                // Link-local 169.254.0.0/16
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
                // Multicast 224.0.0.0/4
                if (bytes[0] >= 224 && bytes[0] <= 239)
                {
                    return true;
                }
                // Broadcast 255.255.255.255
                if (address.Equals(IPAddress.Broadcast))
                {
                    return true;
                }
            }
            else if (address.AddressFamily == AddressFamily.InterNetworkV6)
            {
                // IPv6
                if (address.IsIPv6LinkLocal || address.IsIPv6Multicast || address.IsIPv6SiteLocal || address.IsIPv6Teredo)
                {
                    return true;
                }
                // ::1/128 loopback
                if (address.Equals(IPAddress.IPv6Loopback))
                {
                    return true;
                }
                // Unspecified
                if (address.Equals(IPAddress.IPv6None))
                {
                    return true;
                }
            }
            return false;
        }
    }
}

