using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace YourNamespace.Controllers
{
    // Set up a policy in Program.cs or Startup.cs:
    // services.AddAuthorization(options => { options.AddPolicy("WebhookPolicy", policy => policy.RequireAuthenticatedUser()); });

    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "WebhookPolicy")]
    public class WebhookController : ControllerBase
    {
        private static readonly HashSet<string> AllowedDomains = new(StringComparer.OrdinalIgnoreCase)
        {
            "example.com",
            "api.example.com"
            // Add other approved domains as needed
        };

        private static readonly HashSet<string> AllowedSchemes = new(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly IConfiguration _configuration;

        public WebhookController(IHttpClientFactory httpClientFactory, ILogger<WebhookController> logger, IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost]
        [Route("Fetch")]
        [Authorize(Policy = "WebhookPolicy")]
        public async Task<IActionResult> FetchAsync([FromBody] WebhookRequestDto requestDto)
        {
            _logger.LogInformation("Webhook Fetch requested for target: {Target}", requestDto?.TargetUrl);

            if (requestDto == null || string.IsNullOrWhiteSpace(requestDto.TargetUrl))
            {
                return BadRequest(new { error = "TargetUrl is required." });
            }

            Uri targetUri;
            try
            {
                targetUri = new Uri(requestDto.TargetUrl, UriKind.Absolute);
            }
            catch (UriFormatException)
            {
                _logger.LogWarning("Invalid URL format: {TargetUrl}", requestDto.TargetUrl);
                return BadRequest(new { error = "Invalid URL format." });
            }

            if (!AllowedSchemes.Contains(targetUri.Scheme))
            {
                _logger.LogWarning("Rejected non-HTTPS scheme: {Scheme}", targetUri.Scheme);
                return BadRequest(new { error = "Only HTTPS scheme is allowed." });
            }

            if (!AllowedDomains.Contains(targetUri.Host))
            {
                _logger.LogWarning("Rejected domain not on allowlist: {Host}", targetUri.Host);
                return BadRequest(new { error = "Domain not allowed." });
            }

            if (!IsPublicAddress(targetUri.Host))
            {
                _logger.LogWarning("Rejected non-public address: {Host}", targetUri.Host);
                return BadRequest(new { error = "Target address is not allowed." });
            }

            using var httpClient = _httpClientFactory.CreateClient();
            httpClient.Timeout = TimeSpan.FromSeconds(10);

            var request = new HttpRequestMessage(HttpMethod.Get, targetUri);
            HttpResponseMessage response = null;

            try
            {
                response = await httpClient.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);
                var responseContent = await response.Content.ReadAsStringAsync();
                _logger.LogInformation("Webhook request to {Target} completed with status {StatusCode}", requestDto.TargetUrl, response.StatusCode);
                return Ok(responseContent);
            }
            catch (HttpRequestException ex)
            {
                _logger.LogError(ex, "HTTP request failed to {Target}", requestDto.TargetUrl);
                return StatusCode(500, new { error = "Failed to fetch webhook target." });
            }
            catch (TaskCanceledException)
            {
                _logger.LogWarning("Timeout while fetching {Target}", requestDto.TargetUrl);
                return StatusCode(500, new { error = "Timeout while fetching webhook target." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error while fetching {Target}", requestDto.TargetUrl);
                return StatusCode(500, new { error = "Unexpected error occurred." });
            }
            finally
            {
                response?.Dispose();
            }
        }

        private static bool IsPublicAddress(string host)
        {
            try
            {
                var addresses = Dns.GetHostAddresses(host);
                foreach (var addr in addresses)
                {
                    if (addr.AddressFamily == AddressFamily.InterNetwork || addr.AddressFamily == AddressFamily.InterNetworkV6)
                    {
                        if (IsPrivateOrReservedIp(addr))
                        {
                            return false;
                        }
                    }
                }
                return true;
            }
            catch (SocketException)
            {
                return false;
            }
        }

        private static bool IsPrivateOrReservedIp(IPAddress ip)
        {
            if (IPAddress.IsLoopback(ip))
            {
                return true;
            }

            if (ip.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
                // 127.0.0.0/8 (loopback)
                if (bytes[0] == 127)
                {
                    return true;
                }
                // 0.0.0.0/8 (unspecified)
                if (bytes[0] == 0)
                {
                    return true;
                }
                // 224.0.0.0/4 (multicast)
                if (bytes[0] >= 224 && bytes[0] <= 239)
                {
                    return true;
                }
            }
            else if (ip.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo || ip.IsIPv6UniqueLocal)
                {
                    return true;
                }
                if (ip.Equals(IPAddress.IPv6Loopback) || ip.Equals(IPAddress.IPv6None) || ip.Equals(IPAddress.IPv6Any))
                {
                    return true;
                }
            }
            return false;
        }
    }
}

