using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace WebhookService.Controllers
{
    // Set up a policy named "WebhookPolicy" in your authorization configuration
    [Authorize(Policy = "WebhookPolicy")]
    [ApiController]
    [Route("[controller]")]
    public class WebhookController : ControllerBase
    {
        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly HashSet<string> _allowedHostnames;
        private readonly int _maxContentLength;

        public WebhookController(
            IHttpClientFactory httpClientFactory,
            ILogger<WebhookController> logger,
            IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _allowedHostnames = configuration.GetSection("Webhook:AllowedHostnames").Get<HashSet<string>>() ?? new HashSet<string>();
            _maxContentLength = configuration.GetValue<int>("Webhook:MaxContentLength", 1024 * 1024); // 1MB default
        }

        [Authorize(Policy = "WebhookPolicy")]
        [HttpPost]
        public async Task<IActionResult> PostAsync([FromBody] WebhookRequestDto requestDto)
        {
            _logger.LogInformation("Received webhook request for host {Host}", requestDto?.Host);

            if (requestDto == null)
            {
                return BadRequest(new { error = "Request body is required." });
            }

            if (!IsValidHost(requestDto.Host))
            {
                _logger.LogWarning("Rejected invalid or disallowed host: {Host}", requestDto.Host);
                return BadRequest(new { error = "Invalid or disallowed host." });
            }

            var targetUri = CreateUri(requestDto.Host, requestDto.Path);

            if (!IsSafeUri(targetUri))
            {
                _logger.LogWarning("Rejected unsafe URI: {Uri}", targetUri);
                return BadRequest(new { error = "Unsafe target URI." });
            }

            using var httpClient = _httpClientFactory.CreateClient();
            httpClient.Timeout = TimeSpan.FromSeconds(10);

            var request = new HttpRequestMessage(HttpMethod.Post, targetUri);
            request.Content = new StringContent(requestDto.Data ?? string.Empty, System.Text.Encoding.UTF8, "application/json");
            request.Headers.ExpectContinue = false;

            try
            {
                using var response = await httpClient.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);
                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Webhook request to {Uri} failed with status {Status}", targetUri, response.StatusCode);
                    return StatusCode((int)response.StatusCode, new { error = "Failed to send webhook." });
                }

                var contentLength = response.Content.Headers.ContentLength ?? 0;
                if (contentLength > _maxContentLength)
                {
                    _logger.LogWarning("Webhook response from {Uri} exceeded max length {Length}", targetUri, _maxContentLength);
                    return BadRequest(new { error = "Webhook response too large." });
                }

                _logger.LogInformation("Successfully sent webhook to {Uri}", targetUri);
                return Ok(new { success = true });
            }
            catch (SocketException ex)
            {
                _logger.LogError(ex, "Socket error sending webhook to {Uri}", targetUri);
                return StatusCode(500, new { error = "Failed to connect to target host." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error sending webhook to {Uri}", targetUri);
                return StatusCode(500, new { error = "Internal error sending webhook." });
            }
        }

        private static bool IsValidHost(string host)
        {
            if (string.IsNullOrWhiteSpace(host))
            {
                return false;
            }
            try
            {
                var hostAddresses = Dns.GetHostAddresses(host);
                foreach (var address in hostAddresses)
                {
                    if (IsDisallowedAddress(address))
                    {
                        return false;
                    }
                }
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool IsDisallowedAddress(IPAddress address)
        {
            if (IPAddress.IsLoopback(address))
            {
                return true;
            }
            if (address.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = address.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 127.0.0.0/8
                if (bytes[0] == 127)
                {
                    return true;
                }
                // Link-local 169.254.0.0/16
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
            }
            else if (address.AddressFamily == AddressFamily.InterNetworkV6)
            {
                if (address.IsIPv6LinkLocal || address.IsIPv6Multicast || address.IsIPv6SiteLocal || address.IsIPv6Teredo)
                {
                    return true;
                }
                if (address.Equals(IPAddress.IPv6Loopback) || address.Equals(IPAddress.IPv6None))
                {
                    return true;
                }
            }
            return false;
        }

        private static bool IsSafeUri(Uri uri)
        {
            if (uri == null || !string.Equals(uri.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }
            var host = uri.Host;
            if (!IsValidHost(host))
            {
                return false;
            }
            if (_allowedHostnames.Count > 0 && !_allowedHostnames.Contains(host))
            {
                return false;
            }
            return true;
        }

        private static Uri CreateUri(string host, string path)
        {
            var builder = new UriBuilder
            {
                Scheme = Uri.UriSchemeHttps,
                Host = host,
                Path = path ?? string.Empty
            };
            return builder.Uri;
        }
    }
}

