using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Sockets;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

// Policy setup: In Startup/Program, configure a policy named "WebhookVerify" with appropriate requirements.

namespace YourApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize(Policy = "WebhookVerify")]
    public class WebhookController : ControllerBase
    {
        private static readonly HashSet<string> AllowedHosts = new(StringComparer.OrdinalIgnoreCase)
        {
            // Add business-approved hosts/domains here
            "example.com",
            "api.example.com"
        };

        private static readonly HashSet<string> AllowedSchemes = new(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly IHttpClientFactory _httpClientFactory;
        private readonly ILogger<WebhookController> _logger;
        private readonly IConfiguration _configuration;

        public WebhookController(IHttpClientFactory httpClientFactory, ILogger<WebhookController> logger, IConfiguration configuration)
        {
            _httpClientFactory = httpClientFactory;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost]
        [Route("test")]
        [Authorize(Policy = "WebhookVerify")]
        public async Task<IActionResult> TestWebhook([FromBody] WebhookRequestDto requestDto)
        {
            _logger.LogInformation("Webhook test requested for URL: {Url}", requestDto?.Url);

            if (requestDto == null || string.IsNullOrWhiteSpace(requestDto.Url))
            {
                return BadRequest(new { error = "Missing or invalid webhook URL." });
            }

            if (!TryValidateWebhookUrl(requestDto.Url, out var uri, out var validationError))
            {
                _logger.LogWarning("Webhook URL validation failed: {Error}", validationError);
                return BadRequest(new { error = "Invalid webhook URL." });
            }

            try
            {
                var client = _httpClientFactory.CreateClient(nameof(WebhookController));
                client.Timeout = TimeSpan.FromSeconds(_configuration.GetValue<int?>("Webhook:TimeoutSeconds") ?? 10);
                client.DefaultRequestHeaders.Clear();

                using var httpRequest = new HttpRequestMessage(HttpMethod.Post, uri);
                httpRequest.Content = new StringContent("test", System.Text.Encoding.UTF8, "application/json");

                var response = await client.SendAsync(httpRequest, HttpCompletionOption.ResponseHeadersRead);

                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Webhook request to {Url} failed with status {StatusCode}", uri, response.StatusCode);
                    return StatusCode((int)response.StatusCode, new { error = "Failed to call webhook." });
                }

                _logger.LogInformation("Webhook request to {Url} succeeded.", uri);
                return Ok();
            }
            catch (HttpRequestException ex)
            {
                _logger.LogError(ex, "Error connecting to webhook URL: {Url}", requestDto.Url);
                return StatusCode(500, new { error = "Failed to connect to webhook URL." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error during webhook test.");
                return StatusCode(500, new { error = "Internal server error." });
            }
        }

        private static bool TryValidateWebhookUrl(string url, out Uri uri, out string error)
        {
            uri = null;
            error = null;

            if (!Uri.TryCreate(url, UriKind.Absolute, out uri))
            {
                error = "URL is not a valid absolute URI.";
                return false;
            }

            if (!AllowedSchemes.Contains(uri.Scheme))
            {
                error = "URL scheme is not allowed.";
                return false;
            }

            if (string.IsNullOrWhiteSpace(uri.Host) || !AllowedHosts.Contains(uri.Host))
            {
                error = "Host is not in the allowlist.";
                return false;
            }

            if (!IsPublicAddress(uri.Host))
            {
                error = "Host resolves to a non-public address.";
                return false;
            }

            return true;
        }

        private static bool IsPublicAddress(string host)
        {
            try
            {
                var addresses = Dns.GetHostAddresses(host);
                foreach (var address in addresses)
                {
                    if (address.AddressFamily == AddressFamily.InterNetwork || address.AddressFamily == AddressFamily.InterNetworkV6)
                    {
                        if (IsPrivateOrReserved(address))
                        {
                            return false;
                        }
                    }
                }
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool IsPrivateOrReserved(IPAddress address)
        {
            if (IPAddress.IsLoopback(address))
            {
                return true;
            }

            if (address.AddressFamily == AddressFamily.InterNetwork)
            {
                var bytes = address.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 127.0.0.0/8
                if (bytes[0] == 127)
                {
                    return true;
                }
                // Link-local 169.254.0.0/16
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
            }
            else if (address.AddressFamily == AddressFamily.InterNetworkV6)
            {
                // ::1/128 loopback
                if (address.IsIPv6Loopback)
                {
                    return true;
                }
                // fe80::/10 link-local
                if (address.IsIPv6LinkLocal)
                {
                    return true;
                }
                // fc00::/7 unique local
                var bytes = address.GetAddressBytes();
                if ((bytes[0] & 0xfe) == 0xfc)
                {
                    return true;
                }
                // ::/128 unspecified
                if (address.Equals(IPAddress.IPv6None))
                {
                    return true;
                }
            }
            return false;
        }
    }
}

